<script setup>
import { ref, computed } from 'vue'
import AppLayout from '@/components/Layout/AppLayout.vue'

// State
const loading = ref(false)
const error = ref('')
const saveStatus = ref('')

// ロゴアップロード関連
const logoPreview = ref('')
const logoFile = ref(null)
const logoUploadError = ref('')

const editMode = ref({
  company: false,
  account: false
})

const profile = ref({
  companyName: '外壁リフォーム株式会社',
  representativeName: '田中 太郎',
  contactName: '田中 太郎',
  position: '代表取締役',
  address: '東京都渋谷区神宮前1-1-1 サンプルビル3F',
  phoneNumber: '03-1234-5678',
  mobileNumber: '090-1234-5678',
  email: 'info@gaiheki-reform.co.jp',
  faxNumber: '03-1234-5679',
  licenseNumber: '東京都知事許可（般-1）第12345号',
  businessType: '外壁塗装・リフォーム',
  establishedDate: '2020-04-01',
  website: 'https://gaiheki-reform.co.jp',
  notes: '創業以来、お客様第一をモットーに高品質な外壁塗装サービスを提供しています。',
  logoUrl: '' // ロゴのURL
})

const profileCompleteness = computed(() => {
  const requiredFields = ['companyName', 'representativeName', 'address', 'phoneNumber', 'email']
  const completedFields = requiredFields.filter(field => profile.value[field] && profile.value[field].trim())
  return Math.round((completedFields.length / requiredFields.length) * 100)
})

const companyInfo = ref({
  name: '外壁リフォーム株式会社',
  representative: '田中 太郎',
  address: '東京都渋谷区神宮前1-1-1 サンプルビル3F',
  phone: '03-1234-5678',
  fax: '03-1234-5679',
  email: 'info@gaiheki-reform.co.jp',
  licenseNumber: '東京都知事許可（般-1）第12345号'
})

const accountInfo = ref({
  name: '田中 太郎',
  position: '代表取締役',
  mobile: '090-1234-5678',
  email: 'tanaka@gaiheki-reform.co.jp'
})

const passwordForm = ref({
  current: '',
  new: '',
  confirm: ''
})

const stats = ref({
  totalInquiries: 156,
  completedInquiries: 142,
  totalRevenue: 45600000,
  memberSince: '2022年4月'
})

// Methods
const toggleEditMode = (section) => {
  editMode.value[section] = !editMode.value[section]
  
  if (!editMode.value[section]) {
    // キャンセル時は元の値に戻す処理をここに追加
  }
}

const saveCompanyInfo = () => {
  console.log('会社情報を保存:', companyInfo.value)
  editMode.value.company = false
  // 実際にはAPIに送信
}

const saveAccountInfo = () => {
  console.log('アカウント情報を保存:', accountInfo.value)
  editMode.value.account = false
  // 実際にはAPIに送信
}

const changePassword = () => {
  if (passwordForm.value.new !== passwordForm.value.confirm) {
    alert('新しいパスワードが一致しません')
    return
  }
  
  console.log('パスワード変更')
  // 実際にはAPIに送信
  passwordForm.value = {
    current: '',
    new: '',
    confirm: ''
  }
}

const formatNumber = (num) => {
  return num.toLocaleString('ja-JP')
}

const formatDate = (dateString) => {
  if (!dateString) return ''
  const date = new Date(dateString)
  return date.toLocaleDateString('ja-JP', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  })
}

const clearError = () => {
  error.value = ''
}

const clearSaveStatus = () => {
  saveStatus.value = ''
}

// ロゴアップロード関連メソッド
const handleLogoUpload = (event) => {
  const file = event.target.files[0]
  if (!file) return

  logoUploadError.value = ''

  // ファイル形式チェック
  const allowedTypes = ['image/png', 'image/jpeg', 'image/jpg']
  if (!allowedTypes.includes(file.type)) {
    logoUploadError.value = 'PNG、JPEG、JPG形式のファイルのみ対応しています'
    return
  }

  // ファイルサイズチェック (1MB)
  const maxSize = 1024 * 1024 // 1MB
  if (file.size > maxSize) {
    logoUploadError.value = 'ファイルサイズは1MB以下にしてください'
    return
  }

  logoFile.value = file

  // プレビュー作成
  const reader = new FileReader()
  reader.onload = (e) => {
    logoPreview.value = e.target.result
  }
  reader.readAsDataURL(file)
}

const removeLogo = () => {
  logoPreview.value = ''
  logoFile.value = null
  profile.value.logoUrl = ''
  logoUploadError.value = ''
  
  // ファイル入力をリセット
  const fileInput = document.querySelector('input[type="file"]')
  if (fileInput) {
    fileInput.value = ''
  }
}

const uploadLogoToServer = async () => {
  if (!logoFile.value) return null

  try {
    // Base64形式に変換
    const reader = new FileReader()
    return new Promise((resolve, reject) => {
      reader.onload = () => {
        const base64Data = reader.result.split(',')[1] // data:image/jpeg;base64, の部分を除去
        resolve({
          filename: logoFile.value.name,
          contentType: logoFile.value.type,
          data: base64Data,
          size: logoFile.value.size
        })
      }
      reader.onerror = reject
      reader.readAsDataURL(logoFile.value)
    })
  } catch (error) {
    console.error('Logo upload error:', error)
    throw new Error('ロゴのアップロードに失敗しました')
  }
}

// PDF出力機能
const exportToPDF = async () => {
  try {
    loading.value = true
    
    // html2pdf.js の動的インポート
    const html2pdf = await import('html2pdf.js').then(m => m.default || m)
    
    // PDF用のHTML生成
    const pdfContent = generatePDFContent()
    
    const opt = {
      margin: 1,
      filename: `${profile.value.companyName || '会社'}_プロフィール.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    }
    
    // PDFを生成してダウンロード
    await html2pdf().set(opt).from(pdfContent).save()
    
  } catch (error) {
    console.error('PDF export error:', error)
    error.value = 'PDFの出力に失敗しました'
  } finally {
    loading.value = false
  }
}

const generatePDFContent = () => {
  const logoSection = profile.value.logoUrl || logoPreview.value ? 
    `<div style="text-align: center; margin-bottom: 30px;">
      <img src="${logoPreview.value || profile.value.logoUrl}" 
           style="max-width: 150px; max-height: 150px;" alt="会社ロゴ" />
    </div>` : ''

  return `
    <div style="font-family: 'Noto Sans JP', Arial, sans-serif; line-height: 1.6; color: #333;">
      ${logoSection}
      
      <h1 style="text-align: center; color: #2d3748; border-bottom: 3px solid #3182ce; padding-bottom: 10px;">
        ${profile.value.companyName || '会社名未設定'}
      </h1>
      
      <div style="margin: 30px 0;">
        <h2 style="color: #2d3748; border-left: 4px solid #3182ce; padding-left: 10px;">基本情報</h2>
        <table style="width: 100%; border-collapse: collapse; margin-top: 15px;">
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold; width: 30%;">代表者名</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.representativeName || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">住所</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.address || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">電話番号</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.phoneNumber || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">FAX番号</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.faxNumber || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">メールアドレス</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.email || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">営業許可番号</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.licenseNumber || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">業種</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.businessType || '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">設立年月日</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.establishedDate ? formatDate(profile.value.establishedDate) : '未設定'}</td></tr>
          <tr><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0; font-weight: bold;">ウェブサイト</td><td style="padding: 8px 0; border-bottom: 1px solid #e2e8f0;">${profile.value.website || '未設定'}</td></tr>
        </table>
      </div>
      
      <div style="margin: 30px 0;">
        <h2 style="color: #2d3748; border-left: 4px solid #3182ce; padding-left: 10px;">会社概要</h2>
        <p style="margin-top: 15px; padding: 15px; background-color: #f7fafc; border-radius: 8px;">
          ${profile.value.notes || '会社概要が設定されていません'}
        </p>
      </div>
      
      <div style="margin-top: 50px; text-align: center; font-size: 12px; color: #718096;">
        <p>このプロフィールは ${new Date().toLocaleDateString('ja-JP')} に生成されました</p>
      </div>
    </div>
  `
}
</script>

