<template>
  <div class="app-layout">
    <!-- ヘッダー -->
    <header class="app-header">
      <!-- 管理者モード表示バー -->
      <div v-if="authStore.isAdminMode" class="admin-mode-bar">
        <div class="admin-mode-content">
          <span class="admin-icon">🔧</span>
          <span class="admin-text">管理者モード</span>
          <span v-if="authStore.targetFranchiseName" class="franchise-info">
            {{ authStore.targetFranchiseName }}として操作中
          </span>
          <button @click="exitAdminMode" class="exit-admin-btn">
            管理画面に戻る
          </button>
        </div>
      </div>
      
      <div class="header-content">
        <div class="header-left">
          <button 
            @click="toggleSidebar"
            class="sidebar-toggle"
          >
            <span class="hamburger"></span>
          </button>
          <h1 class="app-title">
            🏢 {{ pageTitle }} - 加盟店管理
          </h1>
        </div>
        
        <div class="header-right">
          <div class="user-menu">
            <button @click="toggleUserMenu" class="user-button">
              <span class="user-name">{{ authStore.displayName }}</span>
              <span class="user-avatar">{{ userInitial }}</span>
            </button>
            
            <div v-if="showUserMenu" class="user-dropdown">
              <router-link to="/profile" class="dropdown-item">
                プロフィール
              </router-link>
              <router-link to="/settings" class="dropdown-item">
                設定
              </router-link>
              <button @click="handleLogout" class="dropdown-item logout">
                ログアウト
              </button>
            </div>
          </div>
        </div>
      </div>
    </header>

    <!-- サイドバー -->
    <aside :class="['app-sidebar', { 'sidebar-open': sidebarOpen }]">
      <nav class="sidebar-nav">
        <router-link
          v-for="item in menuItems"
          :key="item.path"
          :to="item.path"
          class="nav-item"
          :class="{ 'nav-active': $route.path === item.path }"
        >
          <span class="nav-icon">{{ item.icon }}</span>
          <span class="nav-label">{{ item.label }}</span>
        </router-link>
      </nav>
    </aside>

    <!-- メインコンテンツ -->
    <main class="app-main">
      <div class="main-content">
        <slot />
      </div>
    </main>

    <!-- サイドバーオーバーレイ（モバイル用） -->
    <div 
      v-if="sidebarOpen" 
      @click="toggleSidebar"
      class="sidebar-overlay"
    ></div>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, onUnmounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useAuthStore } from '@/stores/auth'

const route = useRoute()
const router = useRouter()
const authStore = useAuthStore()

// State
const sidebarOpen = ref(false)
const showUserMenu = ref(false)

// メニュー項目（加盟店管理システム用）
const menuItems = [
  { path: '/dashboard', label: '管理ダッシュボード', icon: '📊' },
  { path: '/inquiries', label: '案件統括管理', icon: '📋' },
  { path: '/billing', label: '請求・支払い', icon: '💰' },
  { path: '/sub-accounts', label: '子アカウント管理', icon: '👥' },
  { path: '/partner/cancel-request', label: 'キャンセル申請確認', icon: '🚫' },
  { path: '/profile', label: 'プロフィール', icon: '👤' },
  { path: '/settings', label: '設定', icon: '⚙️' }
]

// Computed
const pageTitle = computed(() => {
  const currentItem = menuItems.find(item => item.path === route.path)
  return currentItem?.label || 'メニュー'
})

const userInitial = computed(() => {
  return authStore.displayName?.charAt(0)?.toUpperCase() || 'U'
})

// Methods
const toggleSidebar = () => {
  sidebarOpen.value = !sidebarOpen.value
}

const toggleUserMenu = () => {
  showUserMenu.value = !showUserMenu.value
}

const handleLogout = () => {
  authStore.logout()
  router.push('/login')
}

const exitAdminMode = () => {
  if (confirm('管理者モードを終了して管理画面に戻りますか？')) {
    authStore.exitAdminMode()
  }
}

// クリック外でメニューを閉じる
const handleClickOutside = (event) => {
  if (!event.target.closest('.user-menu')) {
    showUserMenu.value = false
  }
}

onMounted(() => {
  document.addEventListener('click', handleClickOutside)
})

onUnmounted(() => {
  document.removeEventListener('click', handleClickOutside)
})
</script>

