// AI提案エンジン - 営業活動の最適化サポート
export class AIEngine {
  constructor() {
    this.learningData = {
      successPatterns: new Map(),
      customerProfiles: new Map(),
      timeAnalytics: new Map(),
      conversionData: []
    }
    
    // 初期学習データ（模擬）
    this.initializeLearningData()
  }

  // 初期学習データの設定
  initializeLearningData() {
    // 成功パターン
    this.learningData.successPatterns.set('外壁塗装', {
      bestContactTime: { start: 10, end: 11 },
      effectiveApproach: 'deterioration_focus',
      avgCycleDays: 5.2,
      successRate: 0.28
    })
    
    this.learningData.successPatterns.set('屋根修繕', {
      bestContactTime: { start: 9, end: 10 },
      effectiveApproach: 'urgency_focus',
      avgCycleDays: 2.8,
      successRate: 0.35
    })
    
    // 顧客プロファイル
    this.learningData.customerProfiles.set('築30年以上', {
      urgency: 'high',
      budget_sensitive: false,
      decision_speed: 'slow',
      preferred_contact: 'phone'
    })
    
    this.learningData.customerProfiles.set('築15-30年', {
      urgency: 'medium',
      budget_sensitive: true,
      decision_speed: 'medium',
      preferred_contact: 'mixed'
    })
  }

  // メイン提案生成
  generateSuggestions(context) {
    const suggestions = []
    
    // 緊急度分析
    const urgencyAnalysis = this.analyzeUrgency(context)
    if (urgencyAnalysis.score > 0.7) {
      suggestions.push(this.createUrgencySuggestion(urgencyAnalysis))
    }
    
    // タイミング最適化
    const timingAnalysis = this.analyzeOptimalTiming(context)
    if (timingAnalysis.shouldSuggest) {
      suggestions.push(this.createTimingSuggestion(timingAnalysis))
    }
    
    // アプローチ戦略
    const strategyAnalysis = this.analyzeApproachStrategy(context)
    suggestions.push(this.createStrategySuggestion(strategyAnalysis))
    
    // 次回アクション提案
    const nextActionAnalysis = this.analyzeNextAction(context)
    if (nextActionAnalysis.action) {
      suggestions.push(this.createNextActionSuggestion(nextActionAnalysis))
    }
    
    return suggestions.sort((a, b) => b.priority - a.priority)
  }

  // 緊急度分析
  analyzeUrgency(context) {
    let score = 0
    const factors = []
    
    const { case: caseData, lastAction, schedule } = context
    
    // 案件タイプ別緊急度
    if (caseData.title.includes('雨漏り') || caseData.title.includes('緊急')) {
      score += 0.4
      factors.push('緊急性キーワード検出')
    }
    
    // 最後のアクションからの経過時間
    if (lastAction) {
      const hoursSinceLastAction = this.getHoursSince(lastAction.timestamp)
      if (hoursSinceLastAction > 72) {
        score += 0.3
        factors.push('72時間以上未対応')
      } else if (hoursSinceLastAction > 48) {
        score += 0.2
        factors.push('48時間以上未対応')
      }
    }
    
    // 顧客の築年数
    const buildingAge = this.extractBuildingAge(caseData.title, caseData.description)
    if (buildingAge > 25) {
      score += 0.2
      factors.push('築年数による劣化リスク')
    }
    
    // 季節要因
    const month = new Date().getMonth() + 1
    if (month >= 6 && month <= 9) { // 梅雨～台風シーズン
      score += 0.1
      factors.push('気象条件による緊急性')
    }
    
    return {
      score: Math.min(score, 1.0),
      factors,
      level: score > 0.7 ? 'high' : score > 0.4 ? 'medium' : 'low'
    }
  }

  // 最適タイミング分析
  analyzeOptimalTiming(context) {
    const { case: caseData, currentTime = new Date() } = context
    const hour = currentTime.getHours()
    const dayOfWeek = currentTime.getDay()
    
    const workType = this.extractWorkType(caseData.title)
    const pattern = this.learningData.successPatterns.get(workType)
    
    if (!pattern) {
      return { shouldSuggest: false }
    }
    
    const isOptimalTime = hour >= pattern.bestContactTime.start && 
                         hour <= pattern.bestContactTime.end &&
                         dayOfWeek >= 1 && dayOfWeek <= 5
    
    const nextOptimalTime = this.calculateNextOptimalTime(pattern, currentTime)
    
    return {
      shouldSuggest: true,
      isOptimalNow: isOptimalTime,
      nextOptimalTime,
      successRate: pattern.successRate,
      recommendation: isOptimalTime ? 'immediate' : 'scheduled'
    }
  }

  // アプローチ戦略分析
  analyzeApproachStrategy(context) {
    const { case: caseData, customerHistory = [] } = context
    
    const workType = this.extractWorkType(caseData.title)
    const buildingAge = this.extractBuildingAge(caseData.title, caseData.description)
    const customerProfile = this.analyzeCustomerProfile(caseData, customerHistory)
    
    let strategy = {
      primary: 'relationship_building',
      secondary: 'value_demonstration',
      keyPoints: [],
      avoidPoints: [],
      estimatedDuration: 30
    }
    
    // 工事タイプ別戦略
    if (workType === '外壁塗装') {
      strategy.keyPoints.push(
        '現在の外壁状態の詳細確認',
        '前回塗装からの年数と使用塗料',
        '近隣施工実績の紹介',
        '季節や天候による影響説明'
      )
      strategy.estimatedDuration = 45
      
      if (buildingAge > 20) {
        strategy.primary = 'deterioration_focus'
        strategy.keyPoints.unshift('劣化進行のリスクとコスト影響')
      }
    } else if (workType === '屋根修繕') {
      strategy.primary = 'urgency_focus'
      strategy.keyPoints.push(
        '雨漏りの被害範囲確認',
        '応急処置の必要性',
        '保険適用の可能性',
        '二次被害防止の重要性'
      )
      strategy.estimatedDuration = 60
    }
    
    // 顧客プロファイル調整
    if (customerProfile.budget_sensitive) {
      strategy.keyPoints.push('コストパフォーマンスの説明')
      strategy.avoidPoints.push('高額プランの強要')
    }
    
    if (customerProfile.decision_speed === 'slow') {
      strategy.keyPoints.push('検討時間の十分な確保')
      strategy.avoidPoints.push('即決を求める表現')
    }
    
    return strategy
  }

  // 次回アクション分析
  analyzeNextAction(context) {
    const { case: caseData, lastAction, schedule } = context
    
    if (!lastAction) {
      return {
        action: 'initial_contact',
        method: 'phone',
        timing: 'within_2_hours',
        reason: '初回接触による関係構築'
      }
    }
    
    const hoursSinceLastAction = this.getHoursSince(lastAction.timestamp)
    const actionType = lastAction.type
    
    // アクションタイプ別次回提案
    switch (actionType) {
      case 'call':
        if (lastAction.result === 'answered_positive') {
          return {
            action: 'site_survey',
            method: 'visit',
            timing: 'within_24_hours',
            reason: '好感触のため迅速な現地調査'
          }
        } else if (lastAction.result === 'no_answer') {
          return {
            action: 'follow_sms',
            method: 'sms',
            timing: 'within_2_hours',
            reason: '不在フォローアップ'
          }
        }
        break
        
      case 'sms':
        return {
          action: 'follow_call',
          method: 'phone',
          timing: 'within_4_hours',
          reason: 'SMS送信後のフォローアップ'
        }
        
      case 'visit':
        return {
          action: 'estimate_delivery',
          method: 'email',
          timing: 'within_24_hours',
          reason: '現地調査結果の見積もり提供'
        }
        
      default:
        return {
          action: 'status_check',
          method: 'phone',
          timing: 'within_48_hours',
          reason: '進捗状況の確認'
        }
    }
    
    return null
  }

  // 提案生成メソッド群
  createUrgencySuggestion(analysis) {
    return {
      id: `urgency_${Date.now()}`,
      type: 'urgency_alert',
      priority: 9,
      title: '緊急対応が必要',
      message: `この案件は緊急度が高いです（${analysis.level}）。${analysis.factors.join('、')}のため、優先的な対応をお勧めします。`,
      actions: [
        { id: 'immediate_call', icon: '📞', label: '今すぐ電話', type: 'primary' },
        { id: 'priority_schedule', icon: '⚡', label: '優先予定設定', type: 'secondary' }
      ],
      timeLimit: 2 // 2時間以内
    }
  }

  createTimingSuggestion(analysis) {
    if (analysis.isOptimalNow) {
      return {
        id: `timing_now_${Date.now()}`,
        type: 'optimal_timing',
        priority: 8,
        title: '最適タイミング',
        message: `現在は連絡に最適な時間帯です。成功率 ${Math.round(analysis.successRate * 100)}% の実績があります。`,
        actions: [
          { id: 'call_now', icon: '📞', label: '今すぐ電話', type: 'primary' }
        ]
      }
    } else {
      return {
        id: `timing_schedule_${Date.now()}`,
        type: 'timing_optimization',
        priority: 6,
        title: 'タイミング最適化',
        message: `${analysis.nextOptimalTime}が最適な連絡時間です。成功率を最大化するため予約をお勧めします。`,
        actions: [
          { id: 'schedule_optimal', icon: '📅', label: '最適時間に予約', type: 'primary' }
        ]
      }
    }
  }

  createStrategySuggestion(strategy) {
    return {
      id: `strategy_${Date.now()}`,
      type: 'approach_strategy',
      priority: 7,
      title: 'アプローチ戦略',
      message: `推奨アプローチ: ${this.getStrategyLabel(strategy.primary)}。予想所要時間: ${strategy.estimatedDuration}分`,
      details: {
        keyPoints: strategy.keyPoints,
        avoidPoints: strategy.avoidPoints,
        duration: strategy.estimatedDuration
      },
      actions: [
        { id: 'apply_strategy', icon: '🎯', label: '戦略適用', type: 'primary' },
        { id: 'view_details', icon: '📋', label: '詳細確認', type: 'secondary' }
      ]
    }
  }

  createNextActionSuggestion(nextAction) {
    return {
      id: `next_action_${Date.now()}`,
      type: 'next_action',
      priority: 8,
      title: '推奨次回アクション',
      message: `${this.getActionLabel(nextAction.action)}を${this.getTimingLabel(nextAction.timing)}に実行することをお勧めします。`,
      details: {
        action: nextAction.action,
        method: nextAction.method,
        timing: nextAction.timing,
        reason: nextAction.reason
      },
      actions: [
        { id: 'execute_action', icon: this.getActionIcon(nextAction.method), label: '実行', type: 'primary' },
        { id: 'schedule_action', icon: '📅', label: '予約', type: 'secondary' }
      ]
    }
  }

  // 学習・改善機能
  learnFromAction(actionData) {
    const { caseData, actionType, result, timing, duration } = actionData
    
    // 成功パターンの学習
    const workType = this.extractWorkType(caseData.title)
    if (!this.learningData.successPatterns.has(workType)) {
      this.learningData.successPatterns.set(workType, {
        bestContactTime: { start: 10, end: 11 },
        effectiveApproach: 'relationship_building',
        avgCycleDays: 5.0,
        successRate: 0.2
      })
    }
    
    const pattern = this.learningData.successPatterns.get(workType)
    
    // 成功率の更新
    if (result === 'success' || result === 'answered_positive') {
      pattern.successRate = (pattern.successRate * 0.9) + (0.1 * 1.0)
      
      // 成功時の時間帯を学習
      const hour = new Date(timing).getHours()
      if (hour >= 9 && hour <= 17) {
        pattern.bestContactTime = this.updateOptimalTimeRange(pattern.bestContactTime, hour)
      }
    } else {
      pattern.successRate = (pattern.successRate * 0.9) + (0.1 * 0.0)
    }
    
    // コンバージョンデータの記録
    this.learningData.conversionData.push({
      timestamp: new Date().toISOString(),
      workType,
      actionType,
      result,
      hour: new Date(timing).getHours(),
      success: result === 'success' || result === 'answered_positive'
    })
    
    // データサイズ制限（最新1000件）
    if (this.learningData.conversionData.length > 1000) {
      this.learningData.conversionData = this.learningData.conversionData.slice(-1000)
    }
  }

  // パフォーマンス分析
  getPerformanceInsights(timeRange = 30) {
    const cutoffDate = new Date(Date.now() - timeRange * 24 * 60 * 60 * 1000)
    const recentData = this.learningData.conversionData.filter(
      d => new Date(d.timestamp) >= cutoffDate
    )
    
    if (recentData.length === 0) {
      return {
        totalActions: 0,
        successRate: 0,
        bestHour: 10,
        recommendations: ['データが不足しています']
      }
    }
    
    const totalActions = recentData.length
    const successfulActions = recentData.filter(d => d.success).length
    const successRate = (successfulActions / totalActions) * 100
    
    // 時間帯別分析
    const hourlyStats = {}
    recentData.forEach(d => {
      if (!hourlyStats[d.hour]) {
        hourlyStats[d.hour] = { total: 0, success: 0 }
      }
      hourlyStats[d.hour].total++
      if (d.success) hourlyStats[d.hour].success++
    })
    
    let bestHour = 10
    let bestSuccessRate = 0
    Object.entries(hourlyStats).forEach(([hour, stats]) => {
      const rate = stats.success / stats.total
      if (rate > bestSuccessRate && stats.total >= 3) {
        bestSuccessRate = rate
        bestHour = parseInt(hour)
      }
    })
    
    // 推奨事項生成
    const recommendations = []
    if (successRate < 20) {
      recommendations.push('アプローチ方法の見直しをお勧めします')
    }
    if (bestSuccessRate > 0.4) {
      recommendations.push(`${bestHour}時台のアクションが最も効果的です`)
    }
    
    return {
      totalActions,
      successRate: Math.round(successRate),
      bestHour,
      recommendations
    }
  }

  // ヘルパーメソッド
  getHoursSince(timestamp) {
    return (Date.now() - new Date(timestamp).getTime()) / (1000 * 60 * 60)
  }

  extractWorkType(title) {
    if (title.includes('外壁塗装')) return '外壁塗装'
    if (title.includes('屋根')) return '屋根修繕'
    if (title.includes('防水')) return 'ベランダ防水'
    if (title.includes('改装') || title.includes('リフォーム')) return '改装工事'
    return 'その他'
  }

  extractBuildingAge(title, description = '') {
    const text = `${title} ${description}`
    const ageMatch = text.match(/築(\d+)年/)
    return ageMatch ? parseInt(ageMatch[1]) : 15
  }

  analyzeCustomerProfile(caseData, history) {
    const buildingAge = this.extractBuildingAge(caseData.title, caseData.description)
    
    if (buildingAge > 30) {
      return this.learningData.customerProfiles.get('築30年以上') || {}
    } else if (buildingAge > 15) {
      return this.learningData.customerProfiles.get('築15-30年') || {}
    }
    
    return {
      urgency: 'low',
      budget_sensitive: true,
      decision_speed: 'fast',
      preferred_contact: 'mixed'
    }
  }

  calculateNextOptimalTime(pattern, currentTime) {
    const tomorrow = new Date(currentTime)
    tomorrow.setDate(tomorrow.getDate() + 1)
    tomorrow.setHours(pattern.bestContactTime.start, 0, 0, 0)
    
    return tomorrow.toLocaleString('ja-JP', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  updateOptimalTimeRange(currentRange, successHour) {
    // 成功時間帯の範囲を徐々に調整
    const newStart = Math.min(currentRange.start, successHour)
    const newEnd = Math.max(currentRange.end, successHour)
    
    return {
      start: Math.max(9, newStart),
      end: Math.min(17, newEnd)
    }
  }

  getStrategyLabel(strategy) {
    const labels = {
      'relationship_building': '関係構築重視',
      'deterioration_focus': '劣化状況重視',
      'urgency_focus': '緊急性重視',
      'value_demonstration': '価値提案重視'
    }
    return labels[strategy] || strategy
  }

  getActionLabel(action) {
    const labels = {
      'initial_contact': '初回連絡',
      'site_survey': '現地調査',
      'follow_sms': 'SMSフォロー',
      'follow_call': '電話フォロー',
      'estimate_delivery': '見積もり提供',
      'status_check': '状況確認'
    }
    return labels[action] || action
  }

  getTimingLabel(timing) {
    const labels = {
      'within_2_hours': '2時間以内',
      'within_4_hours': '4時間以内',
      'within_24_hours': '24時間以内',
      'within_48_hours': '48時間以内'
    }
    return labels[timing] || timing
  }

  getActionIcon(method) {
    const icons = {
      'phone': '📞',
      'sms': '💬',
      'visit': '🏠',
      'email': '📧'
    }
    return icons[method] || '📋'
  }
}

// シングルトンインスタンス
export const aiEngine = new AIEngine()
export default aiEngine