<script setup>
import { ref, computed, onMounted } from 'vue'
import AppLayout from '@/components/Layout/AppLayout.vue'
import { mockApiService as mockApi } from '@/services/mockApi.js'

// リアクティブデータ
const isLoading = ref(false)
const accounts = ref([])
const searchText = ref('')
const statusFilter = ref('')
const roleFilter = ref('')

// モーダル状態
const showCreateModal = ref(false)
const showEditModal = ref(false)
const isSubmitting = ref(false)
const editingAccount = ref(null)

// フォームデータ
const formData = ref({
  name: '',
  email: '',
  role: '',
  phone: '',
  notes: ''
})

// 計算プロパティ
const isEditMode = computed(() => !!editingAccount.value)

const filteredAccounts = computed(() => {
  let filtered = accounts.value

  if (statusFilter.value) {
    filtered = filtered.filter(account => account.status === statusFilter.value)
  }

  if (roleFilter.value) {
    filtered = filtered.filter(account => account.role === roleFilter.value)
  }

  if (searchText.value) {
    const query = searchText.value.toLowerCase()
    filtered = filtered.filter(account =>
      account.name.toLowerCase().includes(query) ||
      account.email.toLowerCase().includes(query) ||
      getRoleLabel(account.role).toLowerCase().includes(query)
    )
  }

  return filtered
})

// メソッド
const loadAccounts = async () => {
  isLoading.value = true
  try {
    const response = await mockApi.getChildAccounts()
    if (response.success) {
      accounts.value = response.data
    }
  } catch (error) {
    console.error('子アカウント取得エラー:', error)
  } finally {
    isLoading.value = false
  }
}

const editAccount = (account) => {
  editingAccount.value = account
  formData.value = { ...account }
  showEditModal.value = true
}

const viewCases = (account) => {
  // 担当案件表示ロジック
  alert(`${account.name}の担当案件を表示します`)
}

const toggleAccountStatus = async (account) => {
  try {
    const newStatus = account.status === 'active' ? 'inactive' : 'active'
    const response = await mockApi.updateChildAccount({
      id: account.id,
      status: newStatus
    })
    
    if (response.success) {
      account.status = newStatus
      alert(`アカウントを${newStatus === 'active' ? '有効化' : '無効化'}しました`)
    }
  } catch (error) {
    console.error('ステータス更新エラー:', error)
    alert('ステータスの更新に失敗しました')
  }
}

const saveAccount = async () => {
  isSubmitting.value = true
  try {
    const data = isEditMode.value 
      ? { ...formData.value, id: editingAccount.value.id }
      : formData.value

    let response
    if (isEditMode.value) {
      response = await mockApi.updateChildAccount(data)
    } else {
      response = await mockApi.createChildAccount(data)
    }
    
    if (response.success) {
      if (isEditMode.value) {
        // 更新
        const index = accounts.value.findIndex(a => a.id === editingAccount.value.id)
        if (index !== -1) {
          accounts.value[index] = { ...accounts.value[index], ...formData.value }
        }
      } else {
        // 新規作成
        accounts.value.push(response.data)
      }
      
      closeModal()
      alert(isEditMode.value ? '子アカウントを更新しました' : '子アカウントを作成しました')
    }
  } catch (error) {
    console.error('保存エラー:', error)
    alert('保存に失敗しました')
  } finally {
    isSubmitting.value = false
  }
}

const closeModal = () => {
  showCreateModal.value = false
  showEditModal.value = false
  editingAccount.value = null
  formData.value = {
    name: '',
    email: '',
    role: '',
    phone: '',
    notes: ''
  }
}

const getRoleLabel = (role) => {
  const labels = {
    sales: '営業担当',
    manager: 'マネージャー',
    viewer: '閲覧のみ'
  }
  return labels[role] || role
}

const getStatusLabel = (status) => {
  const labels = {
    active: '有効',
    inactive: '無効',
    pending: '承認待ち'
  }
  return labels[status] || status
}

const formatLastLogin = (lastLogin) => {
  if (!lastLogin) return '未ログイン'
  const date = new Date(lastLogin)
  const now = new Date()
  const diffMs = now - date
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24))
  
  if (diffDays === 0) return '今日'
  if (diffDays === 1) return '昨日'
  if (diffDays < 7) return `${diffDays}日前`
  return date.toLocaleDateString('ja-JP')
}

// ライフサイクル
onMounted(() => {
  loadAccounts()
})
</script>

