import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { apiService } from '@/services/api'

export const useAuthStore = defineStore('auth', () => {
  // State
  const user = ref(null)
  const token = ref(localStorage.getItem('franchise_parent_token'))
  const loading = ref(false)
  const error = ref('')
  const isAdminMode = ref(false)
  const adminToken = ref(null)
  const targetFranchiseId = ref(null)
  const targetFranchiseName = ref(null)

  // Getters
  const isAuthenticated = computed(() => !!token.value && !!user.value || isAdminMode.value)
  const userRole = computed(() => {
    if (isAdminMode.value) return 'admin'
    return user.value?.role || 'parent'
  })
  const displayName = computed(() => {
    if (isAdminMode.value && targetFranchiseName.value) {
      return `${targetFranchiseName.value} (管理者モード)`
    }
    return user.value?.name || 'ユーザー'
  })

  // Actions
  const login = async (credentials) => {
    try {
      loading.value = true
      error.value = ''

      const response = await apiService.post('/auth/login', credentials)
      
      if (response && response.success) {
        // GAS APIからの正常レスポンス処理
        token.value = response.data?.token || 'parent-token-' + Date.now()
        user.value = response.data?.user || {
          id: 'parent-' + Date.now(),
          name: '加盟店管理者',
          email: credentials.email,
          role: 'parent'
        }
        
        // トークンをローカルストレージに保存
        localStorage.setItem('franchise_token', token.value)
        
        return true
      } else {
        error.value = response?.message || 'ログインに失敗しました'
        return false
      }
    } catch (err) {
      error.value = err.message || 'ログイン処理でエラーが発生しました'
      return false
    } finally {
      loading.value = false
    }
  }

  const logout = (router = null) => {
    user.value = null
    token.value = null
    localStorage.removeItem('franchise_token')
    
    if (router) {
      router.push('/login')
    }
  }

  const fetchUser = async (router = null) => {
    if (!token.value) return false

    try {
      loading.value = true
      const response = await apiService.get('/auth/me')
      
      if (response.success) {
        user.value = response.data.user
        return true
      } else {
        // トークンが無効な場合はログアウト
        logout(router)
        return false
      }
    } catch (err) {
      console.error('ユーザー情報取得エラー:', err)
      logout(router)
      return false
    } finally {
      loading.value = false
    }
  }

  const clearError = () => {
    error.value = ''
  }

  // 管理者モード用の認証
  const loginAsAdmin = (franchiseId = null, franchiseName = null, adminTokenParam = null) => {
    isAdminMode.value = true
    adminToken.value = adminTokenParam
    targetFranchiseId.value = franchiseId
    targetFranchiseName.value = franchiseName || franchiseId || '管理者'
    
    // 管理者として疑似ユーザーオブジェクトを作成
    user.value = {
      id: 'admin',
      name: displayName.value,
      role: 'admin',
      childId: franchiseId || 'admin',
      isAdminMode: true
    }
    
    console.log('🔧 管理者モードでログイン:', {
      franchiseId,
      franchiseName,
      adminToken: adminTokenParam
    })
  }

  // URLパラメータから管理者認証を確認
  const checkAdminAccess = () => {
    const urlParams = new URLSearchParams(window.location.search)
    const adminTokenParam = urlParams.get('admin_token')
    const franchiseId = urlParams.get('franchise_id')
    const franchiseName = urlParams.get('franchise_name')
    
    if (adminTokenParam && isValidAdminToken(adminTokenParam)) {
      loginAsAdmin(franchiseId, franchiseName, adminTokenParam)
      
      // URLから管理者パラメータを削除（セキュリティ向上）
      const newUrl = new URL(window.location)
      newUrl.searchParams.delete('admin_token')
      newUrl.searchParams.delete('franchise_id') 
      newUrl.searchParams.delete('franchise_name')
      window.history.replaceState({}, '', newUrl)
      
      return true
    }
    
    return false
  }

  // 管理者トークンの検証（簡易版）
  const isValidAdminToken = (token) => {
    // 実際の実装では、サーバーサイドでトークンを検証
    // 現在は形式チェックのみ
    return token && token.startsWith('admin_') && token.length > 20
  }

  // 管理者モードを終了
  const exitAdminMode = () => {
    isAdminMode.value = false
    adminToken.value = null
    targetFranchiseId.value = null
    targetFranchiseName.value = null
    user.value = null
    
    // 通常のログイン画面へリダイレクト
    window.location.href = '/login'
  }

  // 初期化時にユーザー情報を取得
  if (token.value) {
    fetchUser()
  }

  return {
    // State
    user,
    token,
    loading,
    error,
    isAdminMode,
    adminToken,
    targetFranchiseId,
    targetFranchiseName,
    
    // Getters
    isAuthenticated,
    userRole,
    displayName,
    
    // Actions
    login,
    logout,
    fetchUser,
    clearError,
    loginAsAdmin,
    checkAdminAccess,
    exitAdminMode
  }
})