<script setup>
import { ref, computed, onMounted } from 'vue'
import { useAuthStore } from '@/stores/auth'
import { useBillingStore } from '@/stores/billing'
import AppLayout from '@/components/Layout/AppLayout.vue'

// Stores
const authStore = useAuthStore()
const billingStore = useBillingStore()

// Local state
const showPaymentForm = ref(false)
const showBillDetail = ref(false)
const selectedBill = ref(null)
const paymentForm = ref({
  paymentDate: new Date().toISOString().split('T')[0],
  paymentMethod: '',
  notes: ''
})

// Computed
const filteredRecords = computed(() => {
  return billingStore.filteredRecords
})

const summary = computed(() => {
  return billingStore.summary
})

const loading = computed(() => {
  return billingStore.loading
})

const error = computed(() => {
  return billingStore.error
})

// Methods
const refreshBilling = async () => {
  const childId = authStore.user?.childId
  if (childId) {
    await billingStore.fetchBillingRecords(childId)
  }
}

const setPeriodFilter = (period) => {
  billingStore.setFilters({ period })
}

const showPaymentModal = (bill) => {
  selectedBill.value = bill
  paymentForm.value = {
    paymentDate: new Date().toISOString().split('T')[0],
    paymentMethod: '',
    notes: ''
  }
  showBillDetail.value = false
  showPaymentForm.value = true
}

const closePaymentModal = () => {
  showPaymentForm.value = false
  selectedBill.value = null
  paymentForm.value = {
    paymentDate: new Date().toISOString().split('T')[0],
    paymentMethod: '',
    notes: ''
  }
}

const processPayment = async () => {
  if (!selectedBill.value) return
  
  try {
    const success = await billingStore.markAsPaid(selectedBill.value.id, paymentForm.value)
    if (success) {
      closePaymentModal()
      alert('支払い処理が完了しました')
    }
  } catch (err) {
    console.error('Error processing payment:', err)
  }
}

const viewBillDetail = (bill) => {
  selectedBill.value = bill
  showBillDetail.value = true
}

const closeBillModal = () => {
  showBillDetail.value = false
  selectedBill.value = null
}

const downloadInvoice = async (bill) => {
  try {
    const success = await billingStore.downloadInvoice(bill.id)
    if (!success) {
      alert('請求書のダウンロードに失敗しました')
    }
  } catch (err) {
    console.error('Error downloading invoice:', err)
    alert('請求書のダウンロードに失敗しました')
  }
}

const clearError = () => {
  billingStore.clearError()
}

const getPaymentMethodLabel = (method) => {
  const labels = {
    bank_transfer: '銀行振込',
    credit_card: 'クレジットカード',
    cash: '現金',
    other: 'その他'
  }
  return labels[method] || method
}

// Initial load
onMounted(() => {
  refreshBilling()
})
</script>

