<template>
  <AppLayout>
    <div class="cancel-request">
      <!-- ヘッダー -->
      <div class="page-header">
        <h2 class="page-title">
          <span class="page-icon">🚫</span>
          {{ isParentView ? 'キャンセル申請管理' : 'キャンセル申請' }}
        </h2>
        <p class="page-subtitle">
          {{ isParentView ? '加盟店からのキャンセル申請を確認・管理します。' : '案件のキャンセルを申請します。AIがガイドして最適な申請文を作成します。' }}
        </p>
      </div>

      <!-- メインコンテンツ -->
      <div class="main-content">
        <!-- 案件選択セクション -->
        <div class="section-card">
          <div class="section-header">
            <h3 class="section-title">📋 案件選択</h3>
            
            <!-- ステータスフィルター（ラジオボタン） -->
            <div class="status-filter-radio">
              <label class="radio-label">
                <input type="radio" v-model="statusFilter" value="" name="status" />
                <span class="radio-text">全て</span>
              </label>
              <label class="radio-label">
                <input type="radio" v-model="statusFilter" value="new" name="status" />
                <span class="radio-text">新規</span>
              </label>
              <label class="radio-label">
                <input type="radio" v-model="statusFilter" value="in_progress" name="status" />
                <span class="radio-text">対応中</span>
              </label>
              <label class="radio-label">
                <input type="radio" v-model="statusFilter" value="quoted" name="status" />
                <span class="radio-text">見積済</span>
              </label>
            </div>
          </div>
          
          <!-- 案件検索 -->
          <div class="search-area">
            <input
              v-model="searchText"
              type="text"
              class="search-input"
              placeholder="案件名、顧客名、住所、電話番号で検索..."
            />
          </div>

          <!-- 案件リスト -->
          <div class="inquiry-list" :class="{ collapsed: selectedInquiry }">
            <div v-if="isLoadingInquiries" class="loading-state">
              <div class="loading-spinner"></div>
              案件を読み込み中...
            </div>
            
            <div v-else-if="filteredInquiries.length === 0" class="empty-state">
              📋 該当する案件がありません
            </div>
            
            <div v-else>
              <!-- 案件アイテム表示 -->
              <div
                v-for="inquiry in paginatedInquiries"
                :key="inquiry.id"
                class="inquiry-item"
                :class="{ selected: selectedInquiry?.id === inquiry.id }"
                @click="selectInquiry(inquiry)"
              >
                <div class="inquiry-header">
                  <h4 class="inquiry-title">{{ inquiry.title }}</h4>
                  <span :class="['status-badge', inquiry.status]">
                    {{ getStatusLabel(inquiry.status) }}
                  </span>
                </div>
                <div class="inquiry-details">
                  <p>👤 {{ inquiry.customerName }}</p>
                  <p>📍 {{ inquiry.location }}</p>
                  <p>📅 {{ formatDate(inquiry.createdAt) }}</p>
                </div>
              </div>
              
              <!-- ページネーション（選択前のみ表示） -->
              <div v-if="totalPages > 1 && !selectedInquiry" class="pagination">
                <div class="pagination-info">
                  {{ pageInfo.start }}〜{{ pageInfo.end }}件 / 全{{ pageInfo.total }}件
                </div>
                <div class="pagination-controls">
                  <button
                    @click="currentPage = currentPage - 1"
                    :disabled="currentPage === 1"
                    class="pagination-btn"
                  >
                    ← 前
                  </button>
                  <span class="page-numbers">
                    {{ currentPage }} / {{ totalPages }}
                  </span>
                  <button
                    @click="currentPage = currentPage + 1"
                    :disabled="currentPage === totalPages"
                    class="pagination-btn"
                  >
                    次 →
                  </button>
                </div>
              </div>
              
              <!-- 選択中の案件変更ボタン -->
              <div v-if="selectedInquiry" class="change-selection">
                <button @click="clearSelection" class="change-btn">
                  🔄 案件を変更
                </button>
              </div>
            </div>
          </div>
        </div>

        <!-- AI質問セクション -->
        <div v-if="selectedInquiry" class="section-card">
          <h3 class="section-title">🤖 AI質問ガイド</h3>
          
          <!-- AI質問生成中 -->
          <div v-if="isLoadingQuestions" class="ai-loading">
            <div class="loading-content">
              <div class="loading-spinner"></div>
              <h4>🤖 AIが案件に最適な質問を生成中...</h4>
              <p>案件情報: {{ selectedInquiry.title }} - {{ selectedInquiry.customerName }}様</p>
              <div class="loading-steps">
                <div class="step active">📋 案件情報を分析</div>
                <div class="step active">🧠 質問パターンを最適化</div>
                <div class="step active">📝 4つの質問を生成</div>
              </div>
            </div>
          </div>
          
          <div v-else-if="currentQuestion" class="ai-question-area">
            <div class="question-card">
              <h4 class="question-title">{{ currentQuestion.title }}</h4>
              <p class="question-text">{{ currentQuestion.question }}</p>
              
              <div class="choices">
                <button
                  v-for="(choice, index) in currentQuestion.choices"
                  :key="index"
                  class="choice-btn"
                  :class="{ selected: selectedChoices[currentQuestionIndex] === index }"
                  @click="selectChoice(index)"
                >
                  {{ choice.text }}
                </button>
              </div>
              
              <div class="question-nav">
                <!-- 前の質問ボタン（最終質問に回答済みでない限り表示） -->
                <button
                  v-if="currentQuestionIndex > 0 && !(currentQuestionIndex === aiQuestions.length - 1 && selectedChoices[currentQuestionIndex] !== undefined)"
                  @click="previousQuestion"
                  class="btn btn-outline"
                >
                  ← 前の質問
                </button>
                
                <!-- 最終質問完了時の完了メッセージ -->
                <div v-if="currentQuestionIndex === aiQuestions.length - 1 && selectedChoices[currentQuestionIndex] !== undefined" class="completion-message">
                  ✅ ありがとうございました。キャンセル申請文を作成済み
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 申請文＆送信エリア（統合版） -->
        <div v-if="generatedText || customText" class="section-card">
          <h3 class="section-title">📝 キャンセル申請文・送信</h3>
          
          <div class="integrated-text-area">
            <!-- 申請文表示/編集エリア -->
            <div class="text-container">
              <div class="text-header">
                <div class="header-left">
                  <h4 v-if="!editMode">🤖 AI生成申請文</h4>
                  <h4 v-else>✏️ 申請文編集中</h4>
                  <p class="edit-hint">クリックして編集できます</p>
                </div>
                <div class="header-actions">
                  <button v-if="!editMode" @click="regenerateText" class="btn btn-outline btn-sm" :disabled="isGenerating">
                    <span v-if="isGenerating">⏳</span>
                    <span v-else>🔄</span>
                    再生成
                  </button>
                  <button v-if="editMode" @click="improveText" class="btn btn-secondary btn-sm" :disabled="isImproving">
                    <span v-if="isImproving">⏳</span>
                    <span v-else>✨</span>
                    AI改善
                  </button>
                  <button v-if="editMode" @click="finishEditing" class="btn btn-primary btn-sm">
                    ✅ 編集完了
                  </button>
                </div>
              </div>
              
              <!-- 表示モード -->
              <div v-if="!editMode" class="text-display-area" @click="startEditing">
                <div class="text-display clickable">
                  {{ displayText }}
                </div>
                <div class="click-to-edit-overlay">
                  <span class="edit-icon">✏️</span>
                  <span class="edit-text">クリックして編集</span>
                </div>
              </div>
              
              <!-- 編集モード -->
              <div v-else class="text-edit-area">
                <textarea
                  ref="textEditor"
                  v-model="editingText"
                  class="text-editor"
                  rows="12"
                  placeholder="キャンセル申請文を入力してください..."
                  @input="onTextInput"
                ></textarea>
                <div class="edit-info">
                  <span class="char-count">{{ editingText.length }}/2000文字</span>
                  <div class="edit-controls">
                    <button @click="resetToGenerated" class="reset-btn" title="生成文に戻す">
                      🔄 リセット
                    </button>
                  </div>
                </div>
              </div>
            </div>
            
            <!-- 送信エリア -->
            <div class="submit-section">
              <div class="submit-header">
                <h4>📤 申請送信</h4>
                <p class="submit-description">内容を確認して申請を送信してください</p>
              </div>
              
              <div class="submit-actions">
                <button 
                  @click="submitRequest" 
                  class="btn btn-primary btn-lg submit-btn" 
                  :disabled="isSubmitting || !finalText.trim()"
                >
                  <span v-if="isSubmitting" class="submit-loading">
                    <span class="loading-spinner"></span>
                    送信中...
                  </span>
                  <span v-else class="submit-normal">
                    <span class="submit-icon">📤</span>
                    申請を送信
                  </span>
                </button>
              </div>
              
            </div>
          </div>
        </div>

        <!-- 成功メッセージ -->
        <div v-if="showSuccess" class="success-card">
          <div class="success-content">
            <div class="success-icon">✅</div>
            <h3>申請が完了しました</h3>
            <p>申請ID: {{ submissionResult?.requestId }}</p>
            <button @click="resetAll" class="btn btn-primary">
              新しい申請を作成
            </button>
          </div>
        </div>
      </div>
    </div>
  </AppLayout>
</template>

<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { useRoute } from 'vue-router'
import AppLayout from '@/components/Layout/AppLayout.vue'
import { apiService } from '@/services/api'

// ルート情報
const route = useRoute()

// 親アカウントビューかどうかの判定（franchise-parentでは常にtrue）
const isParentView = computed(() => {
  return true // franchise-parentアプリでは常に親ビュー
})

// フランチャイズ親かどうかの判定
const isFranchiseParent = computed(() => {
  return true // franchise-parentアプリでは常に親
})

// フランチャイズ子かどうかの判定
const isFranchiseChild = computed(() => {
  return false // franchise-parentアプリでは常にfalse
})

// リアクティブデータ
const searchText = ref('')
const statusFilter = ref('')
const isLoadingInquiries = ref(false)
const inquiries = ref([])
const selectedInquiry = ref(null)

// ページネーション
const currentPage = ref(1)
const itemsPerPage = ref(10)

// AI質問システム
const currentQuestionIndex = ref(0)
const selectedChoices = ref({})
const isGenerating = ref(false)
const isImproving = ref(false)
const isLoadingQuestions = ref(false)
const aiQuestions = ref([])
const promptSettings = ref(null)

// テキスト管理
const generatedText = ref('')
const customText = ref('')
const editingText = ref('')
const editMode = ref(false)
const showSuccess = ref(false)
const isSubmitting = ref(false)
const submissionResult = ref(null)
const textEditor = ref(null)

// GPT API設定（スプレッドシートから取得）
const loadPromptSettings = async () => {
  try {
    const response = await apiService.get('/getPromptSettings', { 
      category: 'cancel_request',
      type: 'question_generation'
    })
    
    if (response.success) {
      promptSettings.value = response.data
      console.log('プロンプト設定を取得:', promptSettings.value)
    }
  } catch (error) {
    console.error('プロンプト設定取得エラー:', error)
    // フォールバック用のデフォルト設定
    promptSettings.value = {
      questionPrompt: "案件情報に基づいて、キャンセル申請に必要な4つの質問を生成してください。各質問には4つの選択肢を用意してください。",
      textGenerationPrompt: "回答に基づいて、プロフェッショナルなキャンセル申請文を生成してください。"
    }
  }
}

// 計算プロパティ
// 電話番号の正規化関数（ハイフン削除、全角→半角変換）
const normalizePhoneNumber = (phone) => {
  if (!phone) return ''
  return phone
    .replace(/[－‐−ー]/g, '-') // 全角ハイフンを半角に統一
    .replace(/[０-９]/g, (char) => String.fromCharCode(char.charCodeAt(0) - 0xFEE0)) // 全角数字を半角に
    .replace(/[-\s]/g, '') // ハイフンとスペースを削除
    .toLowerCase()
}

const filteredInquiries = computed(() => {
  let filtered = inquiries.value

  if (statusFilter.value) {
    filtered = filtered.filter(inquiry => inquiry.status === statusFilter.value)
  }

  if (searchText.value) {
    const query = searchText.value.toLowerCase()
    const normalizedQuery = normalizePhoneNumber(searchText.value)
    
    filtered = filtered.filter(inquiry => {
      // 基本的な検索（案件名、顧客名、住所）
      const basicMatch = 
        inquiry.title.toLowerCase().includes(query) ||
        inquiry.customerName.toLowerCase().includes(query) ||
        inquiry.location.toLowerCase().includes(query)
      
      // 電話番号検索（正規化して比較）
      const phoneMatch = inquiry.phoneNumber && 
        normalizePhoneNumber(inquiry.phoneNumber).includes(normalizedQuery)
      
      return basicMatch || phoneMatch
    })
  }

  return filtered
})

// ページネーション用の計算プロパティ
const paginatedInquiries = computed(() => {
  // 案件選択後は最大2件のみ表示（選択されたもの + 他1件）
  if (selectedInquiry.value) {
    const selectedItem = filteredInquiries.value.find(item => item.id === selectedInquiry.value.id)
    const otherItems = filteredInquiries.value.filter(item => item.id !== selectedInquiry.value.id)
    
    if (selectedItem) {
      return [selectedItem, ...otherItems.slice(0, 1)]
    }
    return filteredInquiries.value.slice(0, 2)
  }
  
  // 案件選択前は通常のページネーション（10件ずつ）
  const start = (currentPage.value - 1) * itemsPerPage.value
  const end = start + itemsPerPage.value
  return filteredInquiries.value.slice(start, end)
})

const totalPages = computed(() => {
  return Math.ceil(filteredInquiries.value.length / itemsPerPage.value)
})

const pageInfo = computed(() => {
  const start = (currentPage.value - 1) * itemsPerPage.value + 1
  const end = Math.min(start + itemsPerPage.value - 1, filteredInquiries.value.length)
  return {
    start,
    end,
    total: filteredInquiries.value.length
  }
})

const currentQuestion = computed(() => {
  return aiQuestions.value[currentQuestionIndex.value]
})

const allQuestionsAnswered = computed(() => {
  return aiQuestions.value.length > 0 && aiQuestions.value.every((_, index) => selectedChoices.value[index] !== undefined)
})

const finalText = computed(() => {
  return customText.value || generatedText.value
})

const displayText = computed(() => {
  return finalText.value || 'まずはAI質問に答えて申請文を生成してください'
})

// メソッド
const loadInquiries = async () => {
  isLoadingInquiries.value = true
  try {
    const response = await apiService.get('/getInquiriesForChildUser')
    if (response.success) {
      inquiries.value = response.data
    }
  } catch (error) {
    console.error('案件取得エラー:', error)
  } finally {
    isLoadingInquiries.value = false
  }
}

const selectInquiry = async (inquiry) => {
  selectedInquiry.value = inquiry
  currentQuestionIndex.value = 0
  selectedChoices.value = {}
  generatedText.value = ''
  customText.value = ''
  editMode.value = false
  
  // 案件に基づいてAI質問を生成
  await generateAIQuestions(inquiry)
  
  // AI質問セクションまでスクロール
  setTimeout(() => {
    const aiSection = document.querySelector('.ai-question-area')
    if (aiSection) {
      aiSection.scrollIntoView({ behavior: 'smooth', block: 'start' })
    }
  }, 100)
}

// ページネーション関数
const goToPage = (page) => {
  if (page >= 1 && page <= totalPages.value) {
    currentPage.value = page
  }
}

const resetPagination = () => {
  currentPage.value = 1
}

// 案件選択をクリア
const clearSelection = () => {
  selectedInquiry.value = null
  currentQuestionIndex.value = 0
  selectedChoices.value = {}
  generatedText.value = ''
  customText.value = ''
  editMode.value = false
  aiQuestions.value = []
}

// GPT APIでAI質問を生成
const generateAIQuestions = async (inquiry) => {
  isLoadingQuestions.value = true
  
  try {
    const inquiryContext = {
      title: inquiry.title,
      customerName: inquiry.customerName,
      location: inquiry.location,
      status: inquiry.status,
      workType: inquiry.workType || '外壁塗装',
      description: inquiry.description || ''
    }
    
    const response = await apiService.post('/generateAIQuestions', {
      inquiryContext,
      promptSettings: promptSettings.value,
      requestType: 'cancel_request_questions'
    })
    
    if (response.success && response.data.questions) {
      aiQuestions.value = response.data.questions
      console.log('AI質問を生成:', aiQuestions.value)
    } else {
      throw new Error('AI質問の生成に失敗しました')
    }
  } catch (error) {
    console.error('AI質問生成エラー:', error)
    // フォールバック：デフォルト質問を使用
    aiQuestions.value = getDefaultQuestions()
  } finally {
    isLoadingQuestions.value = false
  }
}

// フォールバック用のデフォルト質問
const getDefaultQuestions = () => {
  return [
    {
      title: "キャンセルの主な理由",
      question: "今回のキャンセルの主な理由は何ですか？",
      choices: [
        { text: "お客様からのキャンセル要請", value: "customer_cancel" },
        { text: "連絡が取れない状況", value: "contact_failed" },
        { text: "スケジュール調整困難", value: "schedule_conflict" },
        { text: "その他の理由", value: "other" }
      ]
    },
    {
      title: "経緯・状況",
      question: "どのような経緯でキャンセルに至りましたか？",
      choices: [
        { text: "初回連絡時からの問題", value: "initial_issue" },
        { text: "途中で問題が発生", value: "mid_process_issue" },
        { text: "最終段階での問題", value: "final_stage_issue" },
        { text: "継続的な問題", value: "ongoing_issue" }
      ]
    },
    {
      title: "対応状況",
      question: "これまでどのような対応を行いましたか？",
      choices: [
        { text: "複数回の連絡試行", value: "multiple_contact" },
        { text: "代替案の提示", value: "alternative_proposal" },
        { text: "スケジュール調整の努力", value: "schedule_adjustment" },
        { text: "特別な対応は未実施", value: "no_special_action" }
      ]
    },
    {
      title: "緊急度・影響",
      question: "このキャンセルの緊急度はどの程度ですか？",
      choices: [
        { text: "至急対応が必要", value: "urgent" },
        { text: "1週間以内に対応", value: "within_week" },
        { text: "月内に対応", value: "within_month" },
        { text: "緊急性は低い", value: "not_urgent" }
      ]
    }
  ]
}

const selectChoice = async (choiceIndex) => {
  selectedChoices.value[currentQuestionIndex.value] = choiceIndex
  
  // 少し待ってから次の処理へ（選択した感覚を与える）
  await new Promise(resolve => setTimeout(resolve, 500))
  
  // 最後の質問かチェック
  if (currentQuestionIndex.value === aiQuestions.value.length - 1) {
    // 最終質問 - 自動でAI申請文を生成
    await generateCancelText()
  } else {
    // 次の質問へ自動進行
    nextQuestion()
  }
}

const nextQuestion = () => {
  if (currentQuestionIndex.value < aiQuestions.value.length - 1) {
    currentQuestionIndex.value++
  }
}

const previousQuestion = () => {
  if (currentQuestionIndex.value > 0) {
    currentQuestionIndex.value--
  }
}

const generateCancelText = async () => {
  isGenerating.value = true
  
  try {
    // AI回答を整理
    const answers = aiQuestions.value.map((q, index) => ({
      question: q.title,
      questionText: q.question,
      choice: q.choices[selectedChoices.value[index]]
    }))
    
    const requestData = {
      inquiryContext: {
        title: selectedInquiry.value.title,
        customerName: selectedInquiry.value.customerName,
        location: selectedInquiry.value.location,
        status: selectedInquiry.value.status,
        workType: selectedInquiry.value.workType || '外壁塗装',
        description: selectedInquiry.value.description || ''
      },
      answers,
      promptSettings: promptSettings.value,
      requestType: 'cancel_text_generation'
    }
    
    // GPT APIで申請文を生成
    const response = await apiService.post('/generateCancelText', requestData)
    
    if (response.success && response.data.cancelText) {
      generatedText.value = response.data.cancelText
      console.log('AI申請文を生成:', generatedText.value)
    } else {
      throw new Error('AI申請文の生成に失敗しました')
    }
  } catch (error) {
    console.error('申請文生成エラー:', error)
    // フォールバック：テンプレートベースで生成
    generateFallbackText()
  } finally {
    isGenerating.value = false
    
    // 申請文セクションまでスクロール
    setTimeout(() => {
      const textSection = document.querySelector('.integrated-text-area')
      if (textSection) {
        textSection.scrollIntoView({ behavior: 'smooth', block: 'start' })
      }
    }, 200)
  }
}

// フォールバック用のテンプレート生成
const generateFallbackText = () => {
  const answers = aiQuestions.value.map((q, index) => ({
    question: q.title,
    choice: q.choices[selectedChoices.value[index]]
  }))
  
  generatedText.value = `【${selectedInquiry.value.title} キャンセル申請】

お世話になっております。

以下の案件についてキャンセル申請をさせていただきます。

■ 案件情報
案件名: ${selectedInquiry.value.title}
お客様: ${selectedInquiry.value.customerName}様
所在地: ${selectedInquiry.value.location}

■ 詳細理由
${answers.map(a => `${a.question}: ${a.choice?.text || '未選択'}`).join('\n')}

以上の理由により、やむを得ずキャンセルとさせていただきたく、ご確認のほどよろしくお願いいたします。

申請日時: ${new Date().toLocaleString('ja-JP')}
`
}

const regenerateText = () => {
  generateCancelText()
}

const improveText = async () => {
  isImproving.value = true
  
  try {
    const currentText = editingText.value || customText.value || generatedText.value
    
    const requestData = {
      originalText: currentText,
      inquiryContext: {
        title: selectedInquiry.value.title,
        customerName: selectedInquiry.value.customerName,
        location: selectedInquiry.value.location
      },
      promptSettings: promptSettings.value,
      requestType: 'text_improvement'
    }
    
    // GPT APIで文章改善
    const response = await apiService.post('/improveText', requestData)
    
    if (response.success && response.data.improvedText) {
      if (editMode.value) {
        editingText.value = response.data.improvedText
      } else {
        customText.value = response.data.improvedText
      }
      console.log('AI文章改善完了')
    } else {
      throw new Error('AI文章改善に失敗しました')
    }
  } catch (error) {
    console.error('文章改善エラー:', error)
    // フォールバック：簡単な改善
    const currentText = editingText.value || customText.value || generatedText.value
    const improvedText = `${currentText}

【補足事項】
・より詳細な状況説明が必要な場合は、別途ご連絡いたします
・お客様への配慮を最優先に対応いたします
・今後同様の問題を防ぐための改善策も検討いたします

以上、ご査収のほどよろしくお願いいたします。`
    
    if (editMode.value) {
      editingText.value = improvedText
    } else {
      customText.value = improvedText
    }
  } finally {
    isImproving.value = false
  }
}

const startEditing = () => {
  editMode.value = true
  editingText.value = finalText.value
  // 次のティックでtextareaにフォーカス
  setTimeout(() => {
    textEditor.value?.focus()
  }, 100)
}

const finishEditing = () => {
  customText.value = editingText.value
  editMode.value = false
}

const onTextInput = () => {
  // リアルタイムで文字数制限をチェック
  if (editingText.value.length > 2000) {
    editingText.value = editingText.value.substring(0, 2000)
  }
}

const resetToGenerated = () => {
  if (editMode.value) {
    editingText.value = generatedText.value
  } else {
    customText.value = generatedText.value
    editMode.value = false
  }
}

const submitRequest = async () => {
  isSubmitting.value = true
  
  try {
    const requestData = {
      userId: 'FRANCHISE_001', // TODO: 実際のユーザーIDを取得
      caseId: selectedInquiry.value.id,
      cancelText: finalText.value,
      userName: selectedInquiry.value.customerName || 'キャンセル申請者',
      submittedAt: new Date().toISOString(),
      aiAnswers: selectedChoices.value
    }
    
    // 既存のGAS API（/api/cancel-request）を呼び出し
    const response = await apiService.post('/cancel-request', requestData)
    
    if (response.success) {
      submissionResult.value = {
        success: true,
        requestId: response.data?.id || 'CANCEL_' + Date.now(),
        message: response.message || 'キャンセル申請を送信しました'
      }
      showSuccess.value = true
      
      // 成功メッセージ
      alert('✅ キャンセル申請を送信しました！\nスプレッドシートに記録され、Slack通知も送信されました。')
    } else {
      throw new Error(response.message || 'キャンセル申請の送信に失敗しました')
    }
  } catch (error) {
    console.error('申請送信エラー:', error)
    alert('申請の送信に失敗しました: ' + (error.message || '不明なエラー'))
  } finally {
    isSubmitting.value = false
  }
}

const resetAll = () => {
  selectedInquiry.value = null
  currentQuestionIndex.value = 0
  selectedChoices.value = {}
  generatedText.value = ''
  customText.value = ''
  editMode.value = false
  showSuccess.value = false
  submissionResult.value = null
}

const getStatusLabel = (status) => {
  const labels = {
    new: '新規',
    in_progress: '対応中',
    quoted: '見積済',
    completed: '完了'
  }
  return labels[status] || status
}

const formatDate = (dateString) => {
  const date = new Date(dateString)
  return date.toLocaleDateString('ja-JP', {
    month: 'short',
    day: 'numeric'
  })
}

// 検索・フィルター変更時のページネーションリセット
watch([searchText, statusFilter], () => {
  resetPagination()
})

