import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { apiService } from '@/services/api'

export const useInquiriesStore = defineStore('inquiries', () => {
  
  // State
  const inquiries = ref([])
  const loading = ref(false)
  const error = ref('')
  const filters = ref({
    status: '',
    period: 'month',
    searchText: ''
  })

  // Getters
  const filteredInquiries = computed(() => {
    let filtered = inquiries.value

    // ステータスフィルター
    if (filters.value.status) {
      filtered = filtered.filter(inquiry => inquiry.status === filters.value.status)
    }

    // 期間フィルター
    if (filters.value.period !== 'all') {
      const now = new Date()
      filtered = filtered.filter(inquiry => {
        const inquiryDate = new Date(inquiry.createdAt)
        const daysDiff = Math.floor((now - inquiryDate) / (1000 * 60 * 60 * 24))
        
        switch (filters.value.period) {
          case 'today':
            return daysDiff === 0
          case 'week':
            return daysDiff <= 7
          case 'month':
            return daysDiff <= 30
          default:
            return true
        }
      })
    }

    // 検索テキストフィルター
    if (filters.value.searchText) {
      const searchLower = filters.value.searchText.toLowerCase()
      filtered = filtered.filter(inquiry => 
        inquiry.title.toLowerCase().includes(searchLower) ||
        inquiry.customerName.toLowerCase().includes(searchLower) ||
        inquiry.location.toLowerCase().includes(searchLower)
      )
    }

    return filtered.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
  })

  const statusCounts = computed(() => {
    const counts = {
      all: inquiries.value.length,
      new: 0,
      in_progress: 0,
      quoted: 0,
      completed: 0
    }

    inquiries.value.forEach(inquiry => {
      if (counts[inquiry.status] !== undefined) {
        counts[inquiry.status]++
      }
    })

    return counts
  })

  // Actions
  const fetchInquiries = async (childId) => {
    try {
      loading.value = true
      error.value = ''
      
      const response = await apiService.post('/getInquiriesForChildUser', {
        childId: childId,
        limit: 50
      })

      if (response.success) {
        inquiries.value = response.data || []
      } else {
        throw new Error(response.error || '案件データの取得に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error fetching inquiries:', err)
    } finally {
      loading.value = false
    }
  }

  const updateInquiryStatus = async (inquiryId, newStatus) => {
    try {
      const response = await apiService.post('/updateInquiryStatus', {
        inquiryId: inquiryId,
        status: newStatus
      })

      if (response.success) {
        const inquiry = inquiries.value.find(i => i.id === inquiryId)
        if (inquiry) {
          inquiry.status = newStatus
          inquiry.updatedAt = new Date().toISOString()
        }
        return true
      } else {
        throw new Error(response.error || 'ステータス更新に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error updating inquiry status:', err)
      return false
    }
  }

  const respondToInquiry = async (inquiryId, responseData) => {
    try {
      const response = await apiService.post('/respondToInquiry', {
        inquiryId: inquiryId,
        ...responseData
      })

      if (response.success) {
        await updateInquiryStatus(inquiryId, 'in_progress')
        return true
      } else {
        throw new Error(response.error || '案件対応に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error responding to inquiry:', err)
      return false
    }
  }

  const createQuote = async (inquiryId, quoteData) => {
    try {
      const response = await apiService.post('/createQuote', {
        inquiryId: inquiryId,
        ...quoteData
      })

      if (response.success) {
        await updateInquiryStatus(inquiryId, 'quoted')
        return true
      } else {
        throw new Error(response.error || '見積作成に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error creating quote:', err)
      return false
    }
  }

  const setFilters = (newFilters) => {
    filters.value = { ...filters.value, ...newFilters }
  }

  const clearError = () => {
    error.value = ''
  }

  const getStatusLabel = (status) => {
    const labels = {
      new: '新規',
      in_progress: '対応中',
      quoted: '見積済',
      completed: '完了'
    }
    return labels[status] || '不明'
  }

  const getPriorityLabel = (priority) => {
    const labels = {
      high: '緊急',
      medium: '通常',
      low: '低'
    }
    return labels[priority] || '通常'
  }

  return {
    // State
    inquiries,
    loading,
    error,
    filters,
    
    // Getters
    filteredInquiries,
    statusCounts,
    
    // Actions
    fetchInquiries,
    updateInquiryStatus,
    respondToInquiry,
    createQuote,
    setFilters,
    clearError,
    getStatusLabel,
    getPriorityLabel
  }
})