import { createRouter, createWebHistory } from 'vue-router'
import { useAuthStore } from '@/stores/auth'

// Views
import Login from '@/views/Login.vue'
import Dashboard from '@/views/Dashboard.vue'
import ModernDashboard from '@/views/ModernDashboard.vue'
import Inquiries from '@/views/Inquiries.vue'
import Billing from '@/views/Billing.vue'
import Profile from '@/views/Profile.vue'
import Settings from '@/views/Settings.vue'
import CancelRequest from '@/views/Partner/CancelRequest.vue'
import SubAccounts from '@/views/SubAccounts.vue'
import SubAccountDashboard from '@/views/SubAccount/Dashboard.vue'

const routes = [
  {
    path: '/login',
    name: 'Login',
    component: Login,
    meta: { requiresAuth: false }
  },
  {
    path: '/',
    redirect: '/dashboard'
  },
  {
    path: '/dashboard',
    name: 'Dashboard',
    component: Dashboard,
    meta: { requiresAuth: true }
  },
  {
    path: '/dashboard/legacy',
    name: 'LegacyDashboard',
    component: Dashboard,
    meta: { requiresAuth: true }
  },
  {
    path: '/inquiries',
    name: 'Inquiries',
    component: Inquiries,
    meta: { requiresAuth: true }
  },
  {
    path: '/billing',
    name: 'Billing',
    component: Billing,
    meta: { requiresAuth: true }
  },
  {
    path: '/profile',
    name: 'Profile',
    component: Profile,
    meta: { requiresAuth: true }
  },
  {
    path: '/settings',
    name: 'Settings',
    component: Settings,
    meta: { requiresAuth: true }
  },
  {
    path: '/partner/cancel-request',
    name: 'FranchiseCancelRequest',
    component: CancelRequest,
    meta: { requiresAuth: true, role: 'franchise', title: 'キャンセル申請' }
  },
  {
    path: '/sub-accounts',
    name: 'SubAccounts',
    component: SubAccounts,
    meta: { requiresAuth: true, role: 'parent', title: '子アカウント管理' }
  },
]

const router = createRouter({
  history: createWebHistory(process.env.NODE_ENV === 'production' ? '/franchise-parent/' : '/'),
  routes
})

// ナビゲーションガード
router.beforeEach((to, from, next) => {
  const authStore = useAuthStore()
  
  if (to.meta.requiresAuth && !authStore.isAuthenticated) {
    next('/login')
  } else if (to.name === 'Login' && authStore.isAuthenticated) {
    next('/dashboard')
  } else {
    next()
  }
})

export default router