// 包括的アクションログシステム
export class ActionLogger {
  constructor() {
    this.logs = new Map() // caseId -> logs[]
    this.sessionLogs = []
    this.dailyStats = new Map() // date -> stats
    this.performanceMetrics = {
      totalActions: 0,
      successRate: 0,
      avgResponseTime: 0,
      bestPerformingHours: [],
      conversionFunnel: {
        initial_contact: 0,
        follow_up: 0,
        site_survey: 0,
        estimate: 0,
        contract: 0
      }
    }
    
    this.initializeFromStorage()
  }

  // ストレージからの初期化
  initializeFromStorage() {
    try {
      const storedLogs = localStorage.getItem('actionLogs')
      const storedStats = localStorage.getItem('dailyStats')
      const storedMetrics = localStorage.getItem('performanceMetrics')
      
      if (storedLogs) {
        const parsed = JSON.parse(storedLogs)
        this.logs = new Map(parsed)
      }
      
      if (storedStats) {
        const parsed = JSON.parse(storedStats)
        this.dailyStats = new Map(parsed)
      }
      
      if (storedMetrics) {
        this.performanceMetrics = { ...this.performanceMetrics, ...JSON.parse(storedMetrics) }
      }
    } catch (error) {
      console.error('ログデータの読み込みエラー:', error)
    }
  }

  // ストレージへの保存
  saveToStorage() {
    try {
      localStorage.setItem('actionLogs', JSON.stringify([...this.logs]))
      localStorage.setItem('dailyStats', JSON.stringify([...this.dailyStats]))
      localStorage.setItem('performanceMetrics', JSON.stringify(this.performanceMetrics))
    } catch (error) {
      console.error('ログデータの保存エラー:', error)
    }
  }

  // アクションログの記録
  logAction(actionData) {
    const log = {
      id: this.generateLogId(),
      timestamp: new Date().toISOString(),
      sessionId: this.getCurrentSessionId(),
      ...actionData,
      duration: actionData.duration || 0,
      outcome: actionData.outcome || 'completed',
      metadata: {
        userAgent: navigator.userAgent,
        viewport: `${window.innerWidth}x${window.innerHeight}`,
        timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        ...actionData.metadata
      }
    }

    // 案件別ログに追加
    if (actionData.caseId) {
      if (!this.logs.has(actionData.caseId)) {
        this.logs.set(actionData.caseId, [])
      }
      this.logs.get(actionData.caseId).push(log)
    }

    // セッションログに追加
    this.sessionLogs.push(log)

    // 統計更新
    this.updateStatistics(log)
    
    // ストレージ保存
    this.saveToStorage()

    return log
  }

  // 統計情報の更新
  updateStatistics(log) {
    const today = new Date().toISOString().split('T')[0]
    
    // 日次統計の更新
    if (!this.dailyStats.has(today)) {
      this.dailyStats.set(today, {
        date: today,
        totalActions: 0,
        actionBreakdown: {
          call: 0,
          sms: 0,
          visit: 0,
          email: 0,
          meeting: 0
        },
        successfulActions: 0,
        failedActions: 0,
        avgDuration: 0,
        hourlyDistribution: {},
        conversionEvents: 0
      })
    }

    const todayStats = this.dailyStats.get(today)
    todayStats.totalActions++
    
    // アクションタイプ別カウント
    if (todayStats.actionBreakdown[log.actionType]) {
      todayStats.actionBreakdown[log.actionType]++
    }

    // 成功/失敗カウント
    if (this.isSuccessOutcome(log.outcome)) {
      todayStats.successfulActions++
    } else if (this.isFailureOutcome(log.outcome)) {
      todayStats.failedActions++
    }

    // 時間帯別分布
    const hour = new Date(log.timestamp).getHours()
    todayStats.hourlyDistribution[hour] = (todayStats.hourlyDistribution[hour] || 0) + 1

    // 平均時間の更新
    if (log.duration > 0) {
      const totalDuration = todayStats.avgDuration * (todayStats.totalActions - 1) + log.duration
      todayStats.avgDuration = totalDuration / todayStats.totalActions
    }

    // 全体パフォーマンス指標の更新
    this.updateGlobalMetrics(log)
  }

  // グローバル指標の更新
  updateGlobalMetrics(log) {
    this.performanceMetrics.totalActions++

    // 成功率の更新
    const allLogs = this.getAllLogs()
    const successfulLogs = allLogs.filter(l => this.isSuccessOutcome(l.outcome))
    this.performanceMetrics.successRate = (successfulLogs.length / allLogs.length) * 100

    // 平均応答時間の更新
    const callLogs = allLogs.filter(l => l.actionType === 'call' && l.duration > 0)
    if (callLogs.length > 0) {
      const totalDuration = callLogs.reduce((sum, l) => sum + l.duration, 0)
      this.performanceMetrics.avgResponseTime = totalDuration / callLogs.length
    }

    // 最適時間帯の更新
    this.updateBestPerformingHours()

    // コンバージョンファネルの更新
    this.updateConversionFunnel(log)
  }

  // 最適時間帯の分析
  updateBestPerformingHours() {
    const hourlyPerformance = {}
    
    this.getAllLogs().forEach(log => {
      const hour = new Date(log.timestamp).getHours()
      if (!hourlyPerformance[hour]) {
        hourlyPerformance[hour] = { total: 0, successful: 0 }
      }
      hourlyPerformance[hour].total++
      if (this.isSuccessOutcome(log.outcome)) {
        hourlyPerformance[hour].successful++
      }
    })

    // 成功率でソートして上位3時間を取得
    const rankedHours = Object.entries(hourlyPerformance)
      .map(([hour, stats]) => ({
        hour: parseInt(hour),
        successRate: stats.total > 0 ? (stats.successful / stats.total) : 0,
        total: stats.total
      }))
      .filter(h => h.total >= 3) // 最低3回のアクション
      .sort((a, b) => b.successRate - a.successRate)
      .slice(0, 3)

    this.performanceMetrics.bestPerformingHours = rankedHours
  }

  // コンバージョンファネルの更新
  updateConversionFunnel(log) {
    const stages = {
      'initial_contact': ['call', 'sms', 'email'],
      'follow_up': ['follow_call', 'follow_sms'],
      'site_survey': ['visit', 'survey'],
      'estimate': ['estimate_delivery', 'quote'],
      'contract': ['contract', 'signed']
    }

    for (const [stage, actions] of Object.entries(stages)) {
      if (actions.includes(log.actionType) || actions.includes(log.outcome)) {
        this.performanceMetrics.conversionFunnel[stage]++
        break
      }
    }
  }

  // ケース別ログの取得
  getCaseLogs(caseId) {
    return this.logs.get(caseId) || []
  }

  // 全ログの取得
  getAllLogs() {
    const allLogs = []
    for (const caseLogs of this.logs.values()) {
      allLogs.push(...caseLogs)
    }
    return allLogs.concat(this.sessionLogs.filter(log => !log.caseId))
  }

  // 日次統計の取得
  getDailyStats(date = null) {
    if (date) {
      return this.dailyStats.get(date) || null
    }
    return Array.from(this.dailyStats.values()).sort((a, b) => b.date.localeCompare(a.date))
  }

  // 期間別統計の取得
  getPeriodStats(startDate, endDate) {
    const start = new Date(startDate)
    const end = new Date(endDate)
    
    const periodStats = {
      totalActions: 0,
      successfulActions: 0,
      failedActions: 0,
      avgDuration: 0,
      actionBreakdown: {
        call: 0,
        sms: 0,
        visit: 0,
        email: 0,
        meeting: 0
      },
      dailyTrend: [],
      conversionRate: 0
    }

    for (const [date, stats] of this.dailyStats) {
      const statsDate = new Date(date)
      if (statsDate >= start && statsDate <= end) {
        periodStats.totalActions += stats.totalActions
        periodStats.successfulActions += stats.successfulActions
        periodStats.failedActions += stats.failedActions
        
        // アクション内訳の合計
        for (const actionType in stats.actionBreakdown) {
          periodStats.actionBreakdown[actionType] += stats.actionBreakdown[actionType]
        }
        
        periodStats.dailyTrend.push({
          date: stats.date,
          actions: stats.totalActions,
          successRate: stats.totalActions > 0 ? (stats.successfulActions / stats.totalActions) * 100 : 0
        })
      }
    }

    // 平均値計算
    if (periodStats.totalActions > 0) {
      periodStats.conversionRate = (periodStats.successfulActions / periodStats.totalActions) * 100
    }

    // 日次データをソート
    periodStats.dailyTrend.sort((a, b) => a.date.localeCompare(b.date))

    return periodStats
  }

  // パフォーマンス分析
  getPerformanceAnalysis() {
    const recentLogs = this.getRecentLogs(30) // 30日間
    
    const analysis = {
      overview: {
        totalActions: recentLogs.length,
        successRate: this.calculateSuccessRate(recentLogs),
        avgActionsPerDay: recentLogs.length / 30,
        mostActiveHour: this.getMostActiveHour(recentLogs)
      },
      trends: {
        weeklyTrend: this.getWeeklyTrend(recentLogs),
        actionTypeTrend: this.getActionTypeTrend(recentLogs),
        successRateTrend: this.getSuccessRateTrend(recentLogs)
      },
      insights: this.generateInsights(recentLogs),
      recommendations: this.generateRecommendations(recentLogs)
    }

    return analysis
  }

  // 最近のログ取得
  getRecentLogs(days = 7) {
    const cutoffDate = new Date(Date.now() - days * 24 * 60 * 60 * 1000)
    return this.getAllLogs().filter(log => new Date(log.timestamp) >= cutoffDate)
  }

  // 成功率計算
  calculateSuccessRate(logs) {
    const successfulLogs = logs.filter(log => this.isSuccessOutcome(log.outcome))
    return logs.length > 0 ? (successfulLogs.length / logs.length) * 100 : 0
  }

  // 最も活発な時間帯
  getMostActiveHour(logs) {
    const hourCounts = {}
    logs.forEach(log => {
      const hour = new Date(log.timestamp).getHours()
      hourCounts[hour] = (hourCounts[hour] || 0) + 1
    })

    const mostActiveHour = Object.entries(hourCounts)
      .sort(([,a], [,b]) => b - a)[0]
    
    return mostActiveHour ? parseInt(mostActiveHour[0]) : null
  }

  // 週次トレンド
  getWeeklyTrend(logs) {
    const weeklyData = {}
    logs.forEach(log => {
      const week = this.getWeekKey(new Date(log.timestamp))
      if (!weeklyData[week]) {
        weeklyData[week] = { total: 0, successful: 0 }
      }
      weeklyData[week].total++
      if (this.isSuccessOutcome(log.outcome)) {
        weeklyData[week].successful++
      }
    })

    return Object.entries(weeklyData).map(([week, data]) => ({
      week,
      total: data.total,
      successRate: (data.successful / data.total) * 100
    })).sort((a, b) => a.week.localeCompare(b.week))
  }

  // アクションタイプトレンド
  getActionTypeTrend(logs) {
    const actionCounts = {}
    logs.forEach(log => {
      actionCounts[log.actionType] = (actionCounts[log.actionType] || 0) + 1
    })

    return Object.entries(actionCounts)
      .map(([type, count]) => ({ type, count, percentage: (count / logs.length) * 100 }))
      .sort((a, b) => b.count - a.count)
  }

  // 洞察の生成
  generateInsights(logs) {
    const insights = []

    // 成功率分析
    const successRate = this.calculateSuccessRate(logs)
    if (successRate > 80) {
      insights.push({
        type: 'positive',
        title: '優秀な成果',
        message: `成功率${successRate.toFixed(1)}%は非常に優秀です`
      })
    } else if (successRate < 40) {
      insights.push({
        type: 'warning',
        title: '改善の余地',
        message: `成功率${successRate.toFixed(1)}%は改善の余地があります`
      })
    }

    // 時間帯分析
    const mostActiveHour = this.getMostActiveHour(logs)
    if (mostActiveHour !== null) {
      insights.push({
        type: 'info',
        title: '活動パターン',
        message: `${mostActiveHour}時台が最も活発な時間帯です`
      })
    }

    // アクションバランス
    const actionTrend = this.getActionTypeTrend(logs)
    const dominantAction = actionTrend[0]
    if (dominantAction && dominantAction.percentage > 60) {
      insights.push({
        type: 'suggestion',
        title: 'アクションバランス',
        message: `${dominantAction.type}が${dominantAction.percentage.toFixed(1)}%を占めています。他の手法も試してみましょう`
      })
    }

    return insights
  }

  // 推奨事項の生成
  generateRecommendations(logs) {
    const recommendations = []

    // ベストプラクティス
    const bestHours = this.performanceMetrics.bestPerformingHours
    if (bestHours.length > 0) {
      recommendations.push({
        priority: 'high',
        title: '最適時間帯の活用',
        description: `${bestHours[0].hour}時台の成功率が${(bestHours[0].successRate * 100).toFixed(1)}%と高いです`,
        action: 'この時間帯により多くのアクションを集中させましょう'
      })
    }

    // アクション多様化
    const actionTypes = this.getActionTypeTrend(logs)
    if (actionTypes.length < 3) {
      recommendations.push({
        priority: 'medium',
        title: 'アプローチの多様化',
        description: '使用しているアクションタイプが限定的です',
        action: '電話・SMS・訪問をバランスよく活用しましょう'
      })
    }

    // 継続性
    const recentDays = this.getActiveDays(logs, 7)
    if (recentDays < 5) {
      recommendations.push({
        priority: 'medium',
        title: '活動の継続性',
        description: `直近7日間の活動日数は${recentDays}日です`,
        action: 'より継続的な営業活動を心がけましょう'
      })
    }

    return recommendations
  }

  // ヘルパーメソッド
  generateLogId() {
    return `log_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  }

  getCurrentSessionId() {
    if (!window.sessionStorage.getItem('actionLoggerSessionId')) {
      window.sessionStorage.setItem('actionLoggerSessionId', 
        `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`)
    }
    return window.sessionStorage.getItem('actionLoggerSessionId')
  }

  isSuccessOutcome(outcome) {
    const successOutcomes = [
      'answered_positive', 'contract_signed', 'appointment_scheduled', 
      'estimate_accepted', 'visit_completed', 'follow_up_positive', 'success'
    ]
    return successOutcomes.includes(outcome)
  }

  isFailureOutcome(outcome) {
    const failureOutcomes = [
      'no_answer', 'answered_negative', 'contract_rejected', 
      'appointment_cancelled', 'visit_failed', 'failed'
    ]
    return failureOutcomes.includes(outcome)
  }

  getWeekKey(date) {
    const year = date.getFullYear()
    const week = this.getWeekNumber(date)
    return `${year}-W${week.toString().padStart(2, '0')}`
  }

  getWeekNumber(date) {
    const startOfYear = new Date(date.getFullYear(), 0, 1)
    const days = Math.floor((date - startOfYear) / (24 * 60 * 60 * 1000))
    return Math.ceil((days + startOfYear.getDay() + 1) / 7)
  }

  getActiveDays(logs, period) {
    const uniqueDays = new Set()
    const cutoffDate = new Date(Date.now() - period * 24 * 60 * 60 * 1000)
    
    logs.forEach(log => {
      const logDate = new Date(log.timestamp)
      if (logDate >= cutoffDate) {
        uniqueDays.add(logDate.toISOString().split('T')[0])
      }
    })
    
    return uniqueDays.size
  }

  // データエクスポート
  exportData(format = 'json') {
    const exportData = {
      logs: [...this.logs],
      dailyStats: [...this.dailyStats],
      performanceMetrics: this.performanceMetrics,
      exportedAt: new Date().toISOString()
    }

    if (format === 'json') {
      return JSON.stringify(exportData, null, 2)
    } else if (format === 'csv') {
      return this.convertToCSV(this.getAllLogs())
    }

    return exportData
  }

  convertToCSV(logs) {
    const headers = ['timestamp', 'actionType', 'caseId', 'outcome', 'duration', 'customerName']
    const rows = logs.map(log => [
      log.timestamp,
      log.actionType,
      log.caseId || '',
      log.outcome,
      log.duration || 0,
      log.customerName || ''
    ])

    return [headers, ...rows].map(row => row.map(field => `"${field}"`).join(',')).join('\n')
  }
}

// シングルトンインスタンス
export const actionLogger = new ActionLogger()
export default actionLogger