<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { useAuthStore } from '@/stores/auth'
import { useNotificationsStore } from '@/stores/notifications'
import { apiService } from '@/services/api'
import AppLayout from '@/components/Layout/AppLayout.vue'

// Stores
const authStore = useAuthStore()
const notificationsStore = useNotificationsStore()

// Local state
const originalSettings = ref(null)
const testResults = ref({})
const testingRules = ref(false)

// LINE連携関連の状態
const showQRCodeModal = ref(false)
const checkingConnection = ref(false)
const connectionCheckResult = ref({ success: false })
const lineConnectionStatus = ref({
  connected: false,
  userId: null,
  connectedAt: null
})

// LINE公式アカウントQRコードURL
const QR_URL = 'https://qr-official.line.me/sid/L/052izwwi.png'

// ポーリング用
let connectionCheckInterval = null

// 自動通知ルール
const notificationRules = ref({
  enabled: false,
  paymentDue: {
    enabled: false,
    daysBefore: 3,
    channels: {
      email: true,
      line: false,
      sms: false
    }
  },
  inquiryDelay: {
    enabled: false,
    hoursDelay: 48,
    channels: {
      email: true,
      line: false
    }
  },
  weeklyReport: {
    enabled: false,
    dayOfWeek: 1, // Monday
    hour: 8,
    channels: {
      email: true,
      line: false
    }
  },
  urgentInquiry: {
    enabled: false,
    channels: {
      email: true,
      line: false,
      sms: false
    }
  }
})

// Computed
const settings = computed(() => notificationsStore.settings)
const loading = computed(() => notificationsStore.loading)
const error = computed(() => notificationsStore.error)
const saveStatus = computed(() => notificationsStore.saveStatus)

const hasChanges = computed(() => {
  if (!originalSettings.value) return false
  return JSON.stringify(settings.value) !== JSON.stringify(originalSettings.value)
})

const activeRulesCount = computed(() => {
  if (!notificationRules.value.enabled) return 0
  
  let count = 0
  if (notificationRules.value.paymentDue.enabled) count++
  if (notificationRules.value.inquiryDelay.enabled) count++
  if (notificationRules.value.weeklyReport.enabled) count++
  if (notificationRules.value.urgentInquiry.enabled) count++
  
  return count
})

const hasActiveRules = computed(() => {
  return notificationRules.value.enabled && activeRulesCount.value > 0
})

const hours = Array.from({ length: 24 }, (_, i) => i)

// Methods
const saveAllSettings = async () => {
  const childId = authStore.user?.childId
  if (!childId) return
  
  try {
    // バリデーション
    const validationErrors = notificationsStore.validateSettings()
    if (validationErrors.length > 0) {
      alert('設定エラー:\n' + validationErrors.join('\n'))
      return
    }
    
    // 通知設定保存
    const settingsSuccess = await notificationsStore.updateNotificationSettings(childId)
    
    // 自動通知ルール保存
    const rulesSuccess = await saveNotificationRules()
    
    if (settingsSuccess && rulesSuccess) {
      originalSettings.value = JSON.parse(JSON.stringify(settings.value))
      alert('すべての設定が保存されました')
    }
  } catch (err) {
    alert(`設定の保存に失敗しました: ${err.message}`)
  }
}

const resetToDefaults = () => {
  if (confirm('設定をデフォルトにリセットしますか？')) {
    notificationsStore.resetToDefaults()
  }
}

const refreshSettings = async () => {
  const childId = authStore.user?.childId
  if (childId) {
    await notificationsStore.fetchNotificationSettings(childId)
    await loadNotificationRules()
    originalSettings.value = JSON.parse(JSON.stringify(settings.value))
  }
}

const testNotification = async (type) => {
  const childId = authStore.user?.childId
  if (!childId) return
  
  testResults.value[type] = { loading: true }
  
  try {
    const result = await notificationsStore.testNotification(childId, type)
    testResults.value[type] = result
    
    if (result.success) {
      alert(`${type.toUpperCase()}テスト通知を送信しました`)
    } else {
      alert(`テスト送信に失敗しました: ${result.message}`)
    }
  } catch (err) {
    testResults.value[type] = { success: false, message: err.message }
    alert(`テスト送信エラー: ${err.message}`)
  }
  
  // 3秒後にテスト結果をクリア
  setTimeout(() => {
    delete testResults.value[type]
  }, 3000)
}

const clearError = () => {
  notificationsStore.clearError()
}

const clearSaveStatus = () => {
  notificationsStore.clearSaveStatus()
}

// LINE連携関連メソッド
const closeQRModal = () => {
  showQRCodeModal.value = false
  connectionCheckResult.value = { success: false }
  if (connectionCheckInterval) {
    clearInterval(connectionCheckInterval)
    connectionCheckInterval = null
  }
}

const checkLineConnection = async () => {
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    checkingConnection.value = true
    const response = await apiService.post('/api/line-connected-status', { childId })
    
    if (response.success && response.data.connected) {
      lineConnectionStatus.value = {
        connected: true,
        userId: response.data.userId,
        connectedAt: response.data.connectedAt
      }
      connectionCheckResult.value = { success: true }
      
      // 設定のLINE有効化
      settings.value.line.enabled = true
      
      setTimeout(() => {
        closeQRModal()
      }, 2000)
    }
  } catch (err) {
    console.error('LINE連携確認エラー:', err)
  } finally {
    checkingConnection.value = false
  }
}

const disconnectLine = async () => {
  if (!confirm('LINE連携を解除しますか？')) return
  
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    const response = await apiService.post('/api/disconnect-line', { childId })
    
    if (response.success) {
      lineConnectionStatus.value = {
        connected: false,
        userId: null,
        connectedAt: null
      }
      settings.value.line.enabled = false
      alert('LINE連携を解除しました')
    }
  } catch (err) {
    alert(`連携解除に失敗しました: ${err.message}`)
  }
}

const formatDate = (dateString) => {
  if (!dateString) return ''
  return new Date(dateString).toLocaleString('ja-JP')
}

// QRモーダル表示時に自動でポーリング開始
watch(showQRCodeModal, (newValue) => {
  if (newValue) {
    // 3秒ごとにLINE連携状況をチェック
    connectionCheckInterval = setInterval(() => {
      checkLineConnection()
    }, 3000)
  } else {
    if (connectionCheckInterval) {
      clearInterval(connectionCheckInterval)
      connectionCheckInterval = null
    }
  }
})

// 自動通知ルール関連メソッド
const testNotificationRules = async () => {
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    testingRules.value = true
    
    const response = await apiService.post('/testNotificationRules', {
      childId,
      rules: notificationRules.value
    })

    if (response.success) {
      alert('ルールテストを実行しました。設定された通知方法でテスト通知が送信されます。')
    } else {
      alert(`テスト実行に失敗しました: ${response.message}`)
    }
  } catch (err) {
    alert(`テスト実行エラー: ${err.message}`)
  } finally {
    testingRules.value = false
  }
}

const saveNotificationRules = async () => {
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    const response = await apiService.post('/updateNotificationRules', {
      childId,
      rules: notificationRules.value
    })

    if (response.success) {
      return true
    } else {
      throw new Error(response.message || '自動通知ルールの保存に失敗しました')
    }
  } catch (err) {
    console.error('Error saving notification rules:', err)
    throw err
  }
}

const loadNotificationRules = async () => {
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    const response = await apiService.post('/getNotificationRules', {
      childId
    })

    if (response.success) {
      notificationRules.value = {
        ...notificationRules.value,
        ...response.data
      }
    }
  } catch (err) {
    console.error('Error loading notification rules:', err)
  }
}

// 設定変更を監視して自動保存（オプション）
watch(settings, (newSettings) => {
  // デバウンスしてAPI呼び出しを減らす
  // clearTimeout(autoSaveTimer)
  // autoSaveTimer = setTimeout(() => {
  //   if (hasChanges.value) {
  //     saveAllSettings()
  //   }
  // }, 2000)
}, { deep: true })

// LINE連携状況の初期確認
const loadLineConnectionStatus = async () => {
  const childId = authStore.user?.childId
  if (!childId) return

  try {
    const response = await apiService.post('/api/line-connected-status', { childId })
    
    if (response.success && response.data.connected) {
      lineConnectionStatus.value = {
        connected: true,
        userId: response.data.userId,
        connectedAt: response.data.connectedAt
      }
    }
  } catch (err) {
    console.error('LINE連携状況取得エラー:', err)
  }
}

// 初期読み込み
onMounted(async () => {
  await refreshSettings()
  await loadLineConnectionStatus()
})
