import axios from 'axios'
import { useAuthStore } from '@/stores/auth'
import { mockApiService } from './mockApi'

// GAS WebApp API のベースURL（環境変数から取得）
const BASE_URL = process.env.VUE_APP_GAS_WEBAPP_URL
const MOCK_MODE = process.env.VUE_APP_MOCK_MODE === 'true'

// Axiosインスタンスを作成
const apiClient = axios.create({
  baseURL: BASE_URL,
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  // CORS対応
  withCredentials: false
})

// リクエストインターセプター
apiClient.interceptors.request.use(
  (config) => {
    // 加盟店IDを認証ヘッダーに追加（本番ではJWT想定）
    const authStore = useAuthStore()
    const childId = authStore.user?.childId || localStorage.getItem('franchise_child_id')
    
    if (childId) {
      config.headers.Authorization = `Bearer ${childId}`
    }
    
    // GAS向けにデータを包装
    if (config.method === 'post' && config.data) {
      const path = config.url.startsWith('/api/') ? config.url : `/api${config.url}`
      config.data = JSON.stringify({
        path: path,
        ...config.data
      })
    }
    
    if (process.env.NODE_ENV === 'development') {
      console.log('API Request:', {
        url: config.url,
        method: config.method,
        data: config.data,
        headers: config.headers
      })
    }
    
    return config
  },
  (error) => {
    console.error('Request Error:', error)
    return Promise.reject(error)
  }
)

// レスポンスインターセプター
apiClient.interceptors.response.use(
  (response) => {
    if (process.env.NODE_ENV === 'development') {
      console.log('API Response:', response)
    }
    
    // GASからのレスポンスを解析
    try {
      let responseData = response.data
      
      // 文字列の場合はJSONパース
      if (typeof responseData === 'string') {
        responseData = JSON.parse(responseData)
      }
      
      // GASレスポンス形式に対応
      if (responseData.success !== undefined) {
        return responseData
      }
      
      // 標準的なレスポンス形式に変換
      return {
        success: true,
        data: responseData,
        message: responseData.message || '',
        error: null
      }
    } catch (err) {
      console.error('レスポンス解析エラー:', err)
      return {
        success: false,
        data: null,
        message: 'レスポンス解析に失敗しました',
        error: err.message
      }
    }
  },
  (error) => {
    console.error('API Error:', error)
    
    let errorMessage = 'APIエラーが発生しました'
    let errorCode = null
    
    if (error.response) {
      // サーバーからのエラーレスポンス
      errorCode = error.response.status
      
      try {
        const errorData = typeof error.response.data === 'string'
          ? JSON.parse(error.response.data)
          : error.response.data
        
        errorMessage = errorData.message || errorData.error || `HTTPエラー ${errorCode}`
      } catch {
        errorMessage = `HTTPエラー ${errorCode}`
      }
    } else if (error.request) {
      // リクエストが送信されたが、レスポンスが返ってこない
      errorMessage = 'サーバーに接続できません。ネットワーク接続を確認してください。'
    } else if (error.code === 'ECONNABORTED') {
      // タイムアウト
      errorMessage = 'リクエストがタイムアウトしました。しばらく経ってから再度お試しください。'
    } else {
      // その他のエラー
      errorMessage = error.message || 'リクエストの設定エラー'
    }
    
    return Promise.reject({
      success: false,
      data: null,
      message: errorMessage,
      error: errorMessage,
      code: errorCode
    })
  }
)

// API サービス関数（Composition API対応）
export const useApiService = () => {
  return {
    // GET リクエスト
    async get(endpoint, params = {}) {
      // モックモードの場合
      if (MOCK_MODE) {
        console.log('🎭 Mock Mode: GET', endpoint, params)
        return { data: { success: true, data: null, message: 'Mock response' } }
      }
      
      try {
        const response = await apiClient.get(endpoint, { params })
        return response
      } catch (error) {
        throw error
      }
    },

    // POST リクエスト
    async post(endpoint, data = {}) {
      // モックモードの場合
      if (MOCK_MODE) {
        console.log('🎭 Mock Mode: POST', endpoint, data)
        return { data: { success: true, data: null, message: 'Mock response' } }
      }
      
      try {
        const response = await apiClient.post(endpoint, data)
        return response
      } catch (error) {
        throw error
      }
    },

    // PUT リクエスト
    async put(endpoint, data = {}) {
      try {
        const response = await apiClient.put(endpoint, data)
        return response
      } catch (error) {
        throw error
      }
    },

    // DELETE リクエスト
    async delete(endpoint, data = {}) {
      try {
        const response = await apiClient.delete(endpoint, { data })
        return response
      } catch (error) {
        throw error
      }
    }
  }
}

// モックモード対応のAPI関数マッピング
const mockEndpointMapping = {
  '/auth/login': 'login',
  '/getInquiriesForChildUser': 'getInquiriesForChildUser',
  '/getBillingRecordsForChildUser': 'getBillingRecordsForChildUser', 
  '/getNotificationSettings': 'getNotificationSettings',
  '/updateNotificationSettings': 'updateNotificationSettings',
  '/getChildProfile': 'getChildProfile',
  '/updateChildProfile': 'updateChildProfile',
  '/getChildStatistics': 'getChildStatistics',
  '/changePassword': 'changePassword',
  '/testNotification': 'testNotification',
  '/respondToInquiry': 'respondToInquiry',
  '/createQuote': 'createQuote',
  '/markBillingAsPaid': 'markBillingAsPaid',
  '/downloadInvoice': 'downloadInvoice',
  '/getChatHistoryForInquiry': 'getChatHistoryForInquiry',
  '/getScheduleForChild': 'getScheduleForChild',
  '/saveScheduleForChild': 'saveScheduleForChild',
  '/updateScheduleForChild': 'updateScheduleForChild',
  '/deleteScheduleForChild': 'deleteScheduleForChild',
  '/getNotificationRules': 'getNotificationRules',
  '/updateNotificationRules': 'updateNotificationRules',
  '/testNotificationRules': 'testNotificationRules',
  '/api/line-connected-status': 'getLineConnectedStatus',
  '/api/disconnect-line': 'disconnectLine',
  '/getLineTemplates': 'getLineTemplates',
  '/saveLineTemplate': 'saveLineTemplate',
  '/generateAITemplate': 'generateAITemplate',
  '/testLineNotification': 'testLineNotification',
  '/cancel-request': 'cancelRequest'
}

// レガシーサポート用（モックモード対応）
export const apiService = {
  async get(endpoint, params = {}) {
    if (MOCK_MODE && mockEndpointMapping[endpoint]) {
      const mockMethod = mockEndpointMapping[endpoint]
      if (mockApiService[mockMethod]) {
        return await mockApiService[mockMethod](params.childId || 'test-child-id', params)
      }
    }
    return useApiService().get(endpoint, params)
  },
  async post(endpoint, data = {}) {
    console.log('🔍 Parent API - MOCK_MODE:', MOCK_MODE, 'BASE_URL:', BASE_URL, 'endpoint:', endpoint)
    
    if (MOCK_MODE && mockEndpointMapping[endpoint]) {
      const mockMethod = mockEndpointMapping[endpoint]
      if (mockApiService[mockMethod]) {
        try {
          // ログインの場合は特別な処理
          if (endpoint === '/auth/login') {
            return await mockApiService[mockMethod](data)
          }
          // その他のエンドポイント
          const childId = data.childId || 'test-child-id'
          return await mockApiService[mockMethod](childId, data)
        } catch (error) {
          console.error('Mock API Error:', error)
          return {
            success: false,
            data: null,
            message: 'モックAPIでエラーが発生しました',
            error: error.message || 'Unknown error'
          }
        }
      }
    }
    
    // GAS WebApp GET方式で呼び出し
    try {
      const params = new URLSearchParams({
        action: endpoint.replace('/api/', '').replace('/', ''),
        role: 'parent',
        ...data
      })
      
      const response = await fetch(`${BASE_URL}?${params}`, {
        method: 'GET',
        mode: 'cors'
      })
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`)
      }
      
      const text = await response.text()
      console.log('🔍 Raw GAS Response:', text)
      
      let result
      try {
        result = JSON.parse(text)
      } catch (parseError) {
        if (text.includes('success') || text.includes('true')) {
          result = { success: true, data: { token: 'gas-token-' + Date.now(), user: { email: data.email, role: 'parent' } } }
        } else {
          result = { success: false, message: 'GAS APIレスポンス形式エラー' }
        }
      }
      
      console.log('🔍 Parsed GAS Response:', result)
      return result
    } catch (error) {
      console.error('🚨 API error:', error)
      return { success: false, message: 'ネットワークエラー: ' + error.message }
    }
  },
  async put(endpoint, data = {}) {
    if (MOCK_MODE && mockEndpointMapping[endpoint]) {
      const mockMethod = mockEndpointMapping[endpoint]
      if (mockApiService[mockMethod]) {
        const childId = data.childId || 'test-child-id'
        return await mockApiService[mockMethod](childId, data)
      }
    }
    return useApiService().put(endpoint, data)
  },
  async delete(endpoint, data = {}) {
    if (MOCK_MODE && mockEndpointMapping[endpoint]) {
      const mockMethod = mockEndpointMapping[endpoint]
      if (mockApiService[mockMethod]) {
        const childId = data.childId || 'test-child-id'
        return await mockApiService[mockMethod](childId, data)
      }
    }
    return useApiService().delete(endpoint, data)
  },
  
  // キャンセル申請専用メソッド
  async submitCancelRequest(requestData) {
    if (MOCK_MODE) {
      return await mockApiService.cancelRequest('test-child-id', requestData)
    }
    return this.post('/cancel-request', requestData)
  }
}

export default apiService