import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { apiService } from '@/services/api'

export const useBillingStore = defineStore('billing', () => {
  
  // State
  const billingRecords = ref([])
  const loading = ref(false)
  const error = ref('')
  const filters = ref({
    status: '',
    period: 'month'
  })

  // Getters
  const filteredRecords = computed(() => {
    let filtered = billingRecords.value

    // ステータスフィルター
    if (filters.value.status) {
      filtered = filtered.filter(record => record.status === filters.value.status)
    }

    // 期間フィルター
    if (filters.value.period !== 'all') {
      const now = new Date()
      filtered = filtered.filter(record => {
        const recordDate = new Date(record.billingDate)
        const monthsDiff = (now.getFullYear() - recordDate.getFullYear()) * 12 + 
                          (now.getMonth() - recordDate.getMonth())
        
        switch (filters.value.period) {
          case 'month':
            return monthsDiff <= 1
          case 'quarter':
            return monthsDiff <= 3
          case 'year':
            return monthsDiff <= 12
          default:
            return true
        }
      })
    }

    return filtered.sort((a, b) => new Date(b.billingDate) - new Date(a.billingDate))
  })

  const summary = computed(() => {
    const result = {
      totalAmount: 0,
      paidAmount: 0,
      pendingAmount: 0,
      overdueAmount: 0,
      pendingCount: 0,
      paidCount: 0,
      overdueCount: 0
    }

    billingRecords.value.forEach(record => {
      result.totalAmount += record.amount || 0

      switch (record.status) {
        case 'paid':
          result.paidAmount += record.amount || 0
          result.paidCount++
          break
        case 'pending':
          result.pendingAmount += record.amount || 0
          result.pendingCount++
          break
        case 'overdue':
          result.overdueAmount += record.amount || 0
          result.overdueCount++
          break
      }
    })

    return result
  })

  // Actions
  const fetchBillingRecords = async (childId) => {
    try {
      loading.value = true
      error.value = ''
      
      const response = await apiService.post('/getBillingRecordsForChildUser', {
        childId: childId
      })

      if (response.success) {
        billingRecords.value = (response.data || []).map(record => ({
          ...record,
          // 支払い期限を計算（末締め→翌月27日）
          dueDate: calculateDueDate(record.billingDate),
          // ステータスを更新（期限切れチェック）
          status: updateRecordStatus(record)
        }))
      } else {
        throw new Error(response.error || '請求データの取得に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error fetching billing records:', err)
    } finally {
      loading.value = false
    }
  }

  const markAsPaid = async (billingId, paymentData) => {
    try {
      const response = await apiService.post('/markBillingAsPaid', {
        billingId: billingId,
        paymentDate: paymentData.paymentDate || new Date().toISOString(),
        paymentMethod: paymentData.paymentMethod || '',
        notes: paymentData.notes || ''
      })

      if (response.success) {
        const record = billingRecords.value.find(r => r.id === billingId)
        if (record) {
          record.status = 'paid'
          record.paidDate = paymentData.paymentDate || new Date().toISOString()
          record.paymentMethod = paymentData.paymentMethod || ''
          record.notes = paymentData.notes || ''
        }
        return true
      } else {
        throw new Error(response.error || '支払い処理に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error marking as paid:', err)
      return false
    }
  }

  const downloadInvoice = async (billingId) => {
    try {
      const response = await apiService.post('/downloadInvoice', {
        billingId: billingId
      })

      if (response.success && response.data.downloadUrl) {
        // PDFダウンロード処理
        const link = document.createElement('a')
        link.href = response.data.downloadUrl
        link.download = `invoice-${billingId}.pdf`
        document.body.appendChild(link)
        link.click()
        document.body.removeChild(link)
        return true
      } else {
        throw new Error(response.error || '請求書のダウンロードに失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error downloading invoice:', err)
      return false
    }
  }

  const setFilters = (newFilters) => {
    filters.value = { ...filters.value, ...newFilters }
  }

  const clearError = () => {
    error.value = ''
  }

  // Helper functions
  const calculateDueDate = (billingDate) => {
    const date = new Date(billingDate)
    // 末締め→翌月27日
    const dueDate = new Date(date.getFullYear(), date.getMonth() + 1, 27)
    return dueDate.toISOString()
  }

  const updateRecordStatus = (record) => {
    if (record.status === 'paid') {
      return 'paid'
    }

    const dueDate = new Date(record.dueDate || calculateDueDate(record.billingDate))
    const now = new Date()

    if (now > dueDate) {
      return 'overdue'
    }

    return 'pending'
  }

  const getStatusLabel = (status) => {
    const labels = {
      paid: '支払済',
      pending: '未払い',
      overdue: '期限切れ'
    }
    return labels[status] || '不明'
  }

  const formatAmount = (amount) => {
    return new Intl.NumberFormat('ja-JP', {
      style: 'currency',
      currency: 'JPY',
      minimumFractionDigits: 0
    }).format(amount || 0)
  }

  const formatDate = (dateString) => {
    if (!dateString) return ''
    const date = new Date(dateString)
    return date.toLocaleDateString('ja-JP')
  }

  return {
    // State
    billingRecords,
    loading,
    error,
    filters,
    
    // Getters
    filteredRecords,
    summary,
    
    // Actions
    fetchBillingRecords,
    markAsPaid,
    downloadInvoice,
    setFilters,
    clearError,
    getStatusLabel,
    formatAmount,
    formatDate
  }
})